    </div>
  ) : null

  // 主内容：如果 visible 为 true（编辑模态框打开），则隐藏 children；否则显示 children
  const content = visible ? null : children

  // 编辑模态框（简化版，实际项目中可能需要使用 Modal 组件）
  const editModal = visible ? (
    <div
      style={{
        position: "fixed",
        top: 0,
        left: 0,
        width: "100vw",
        height: "100vh",
        backgroundColor: "rgba(0,0,0,0.5)",
        zIndex: 1000,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      <div
        style={{
          width: layoutWidth,
          height: layoutHeight,
          backgroundColor: "#fff",
          border: "1px solid #ccc",
          padding: 0,
          overflow: "hidden",
        }}
      >
        <div style={{ padding: "16px", display: "flex", justifyContent: "space-between" }}>
          <span>编辑三维组件组</span>
          <button onClick={handleCloseModal}>关闭</button>
        </div>
        <div
          className="dashboard-cell-select"
          style={{ width: layoutWidth, height: layoutHeight - 50, border: "1px solid #ccc" }}
        >
          {React.useMemo(() => children, [])}
        </div>
      </div>
    </div>
  ) : null

  // 如果没有 setMeshs，说明不在三维空间中使用，显示提示
  if (!setMeshs) {
    return (
      <Html
        transform={!isFixd}
        sprite={!!isSprite}
        distanceFactor={200}
        scale={[scale?.x || 1, scale?.y || 1, scale?.z || 1]}
        position={[position?.x || 0, position?.y || 0, position?.z || 0]}
        rotation={[
          THREE.MathUtils.degToRad(rotation?.x || 0),
          THREE.MathUtils.degToRad(rotation?.y || 0),
          THREE.MathUtils.degToRad(rotation?.z || 0),
        ]}
      >
        <div className={cn("layout_3d", className)} style={{ color: "#999" }}>
          请放入三维空间中使用
        </div>
      </Html>
    )
  }

  const htmlContent = (
    <div
      ref={cardRef}
      className={cn("layout_3d", className)}
      style={{
        width: layoutWidth,
        height: layoutHeight,
        border: editMode ? "1px solid #CCCCCC" : "none",
        overflow: "hidden",
        position: "relative",
      }}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      onDoubleClick={handleDoubleClick}
    >
      {maskElement}
      {content}
      {editModal}
    </div>
  )

  return (
    <Html
      transform={!isFixd}
      sprite={!!isSprite}
      distanceFactor={200}
      scale={[scale?.x || 1, scale?.y || 1, scale?.z || 1]}
      position={[position?.x || 0, position?.y || 0, position?.z || 0]}
      rotation={[
        THREE.MathUtils.degToRad(rotation?.x || 0),
        THREE.MathUtils.degToRad(rotation?.y || 0),
        THREE.MathUtils.degToRad(rotation?.z || 0),
      ]}
    >
      {htmlContent}
    </Html>
  )
}

