import * as React from "react"
import { Calendar } from "@/components/ui/calendar"
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover"
import { Button } from "@/components/ui/button"
import { cn } from "@/lib/utils"
import { format as formatFn } from "date-fns"
import { zhCN } from "date-fns/locale"

export interface DateRangeProps {
  /**
   * 日期格式：date-日期, datetime-日期时间, time-时间
   */
  format?: 'date' | 'datetime' | 'time'
  /**
   * 是否禁用
   */
  disabled?: boolean
  /**
   * 值
   */
  value?: string
  /**
   * 变化回调
   */
  onChange?: (value: string | null) => void
  /**
   * 占位符
   */
  placeholder?: string
  /**
   * 单元格键值
   */
  cellKey?: string
}

const DateRange = React.forwardRef<HTMLDivElement, DateRangeProps>(
  (
    {
      format = 'date',
      disabled = false,
      value,
      onChange,
      placeholder = '请选择日期范围',
      cellKey,
      className,
      ...props
    },
    ref
  ) => {
    const [startDate, setStartDate] = React.useState<Date | undefined>(undefined)
    const [endDate, setEndDate] = React.useState<Date | undefined>(undefined)
    const [isStartOpen, setIsStartOpen] = React.useState(false)
    const [isEndOpen, setIsEndOpen] = React.useState(false)

    React.useEffect(() => {
      if (value && value.includes(' - ')) {
        const [start, end] = value.split(' - ')
        if (start) setStartDate(new Date(start))
        if (end) setEndDate(new Date(end))
      } else if (!value) {
        setStartDate(undefined)
        setEndDate(undefined)
      }
    }, [value])

    const handleStartDateChange = (date: Date | undefined) => {
      setStartDate(date)
      if (endDate) {
        const startStr = formatRangeValue(date, endDate)
        onChange?.(startStr)
      } else {
        onChange?.(date ? formatRangeValue(date, undefined) : null)
      }
      setIsStartOpen(false)
    }

    const handleEndDateChange = (date: Date | undefined) => {
      setEndDate(date)
      if (startDate) {
        const endStr = formatRangeValue(startDate, date)
        onChange?.(endStr)
      } else {
        onChange?.(date ? formatRangeValue(undefined, date) : null)
      }
      setIsEndOpen(false)
    }

    const formatRangeValue = (start: Date | undefined, end: Date | undefined): string | null => {
      if (!start && !end) return null
      if (!start) return ` - ${formatDateValue(end!, format)}`
      if (!end) return `${formatDateValue(start!, format)} - `
      return `${formatDateValue(start!, format)} - ${formatDateValue(end!, format)}`
    }

    const formatDateValue = (date: Date, formatType: string): string => {
      const dateObj = new Date(date)
      if (formatType === 'date') {
        return formatFn(dateObj, 'yyyy-MM-dd')
      } else if (formatType === 'datetime') {
        return formatFn(dateObj, 'yyyy-MM-dd HH:mm:ss')
      } else if (formatType === 'time') {
        return formatFn(dateObj, 'HH:mm:ss')
      }
      return formatFn(dateObj, 'yyyy-MM-dd')
    }

    const handleClear = () => {
      setStartDate(undefined)
      setEndDate(undefined)
      onChange?.(null)
    }

    return (
      <div
        ref={ref}
        className={cn(
          "date-range-component flex items-center gap-2 w-full",
          disabled && "opacity-50 pointer-events-none",
          className
        )}
        {...props}
      >
        <Popover open={isStartOpen} onOpenChange={setIsStartOpen}>
          <PopoverTrigger asChild>
            <Button
              variant="outline"
              disabled={disabled}
              className={cn(
                "justify-start text-left font-normal",
                !startDate && "text-muted-foreground"
              )}
            >
              {startDate ? formatDateValue(startDate, format) : <span>{placeholder}</span>}
            </Button>
          </PopoverTrigger>
          <PopoverContent className="w-auto p-0" align="start">
            {format === 'date' && (
              <Calendar
                mode="single"
                selected={startDate}
                onSelect={handleStartDateChange}
                initialFocus
              />
            )}
            {format === 'datetime' && (
              <div className="flex gap-2 p-2">
                <Calendar
                  mode="single"
                  selected={startDate}
                  onSelect={handleStartDateChange}
                  initialFocus
                  locale={zhCN}
                />
                <input
                  type="time"
                  value={startDate ? formatFn(startDate, 'HH:mm:ss') : ''}
                  onChange={(e) => {
                    if (startDate) {
                      const [hours='00', minutes='00', seconds='00'] = e.target.value.split(':')
                      const newDate = new Date(startDate)
                      newDate.setHours(Number(hours), Number(minutes), Number(seconds))
                      handleStartDateChange(newDate)
                    }
                  }}
                  className="border rounded px-2 py-1"
                />
              </div>
            )}
            {format === 'time' && (
              <div className="flex gap-2 p-2">
                <input
                  type="time"
                  value={startDate ? formatFn(startDate, 'HH:mm:ss') : ''}
                  onChange={(e) => {
                    const [hours='00', minutes='00', seconds='00'] = e.target.value.split(':')
                    const newDate = new Date()
                    newDate.setHours(Number(hours), Number(minutes), Number(seconds))
                    handleStartDateChange(newDate)
                  }}
                  className="border rounded px-2 py-1"
                />
              </div>
            )}
          </PopoverContent>
        </Popover>

        <span className="text-slate-400">-</span>

        <Popover open={isEndOpen} onOpenChange={setIsEndOpen}>
          <PopoverTrigger asChild>
            <Button
              variant="outline"
              disabled={disabled}
              className={cn(
                "justify-start text-left font-normal",
                !endDate && "text-muted-foreground"
              )}
            >
              {endDate ? formatDateValue(endDate, format) : <span>{placeholder}</span>}
            </Button>
          </PopoverTrigger>
          <PopoverContent className="w-auto p-0" align="start">
            {format === 'date' && (
              <Calendar
                mode="single"
                selected={endDate}
                onSelect={handleEndDateChange}
                initialFocus
              />
            )}
            {format === 'datetime' && (
              <div className="flex gap-2 p-2">
                <Calendar
                  mode="single"
                  selected={endDate}
                  onSelect={handleEndDateChange}
                  initialFocus
                  locale={zhCN}
                />
                <input
                  type="time"
                  value={endDate ? formatFn(endDate, 'HH:mm:ss') : ''}
                  onChange={(e) => {
                    if (endDate) {
                      const [hours='00', minutes='00', seconds='00'] = e.target.value.split(':')
                      const newDate = new Date(endDate)
                      newDate.setHours(Number(hours), Number(minutes), Number(seconds))
                      handleEndDateChange(newDate)
                    }
                  }}
                  className="border rounded px-2 py-1"
                />
              </div>
            )}
            {format === 'time' && (
              <div className="flex gap-2 p-2">
                <input
                  type="time"
                  value={endDate ? formatFn(endDate, 'HH:mm:ss') : ''}
                  onChange={(e) => {
                    const [hours='00', minutes='00', seconds='00'] = e.target.value.split(':')
                    const newDate = new Date()
                    newDate.setHours(Number(hours), Number(minutes), Number(seconds))
                    handleEndDateChange(newDate)
                  }}
                  className="border rounded px-2 py-1"
                />
              </div>
            )}
          </PopoverContent>
        </Popover>

        {(startDate || endDate) && (
          <Button
            onClick={handleClear}
            disabled={disabled}
            variant="ghost"
            size="icon"
            className="text-slate-400 hover:text-slate-600"
            title="清除"
          >
            ×
          </Button>
        )}
      </div>
    )
  }
)

DateRange.displayName = "DateRange"

export default DateRange

import { Button } from "@/components/ui/button"
import {
  Field,
  FieldDescription,
  FieldError,
  FieldLabel,
} from "@/components/ui/field"
import { Input } from '@/components/ui/input'
import { Controller, useFieldUIStateValue, useFormContext } from '@airiot/client'
import type { ReactNode } from 'react'
import React, { cloneElement } from 'react'
import fieldMap from './field-map'
import { cn } from '@/lib/utils'

type FormFieldProps = {
  name: string
  label?: ReactNode
  type?: string
  description?: ReactNode
  children?: ReactNode | ((props: any) => ReactNode)
  required?: boolean
  rules?: any
  className?: string
  classNames?: Record<'field' | 'label' | 'input' | 'description' | 'error', string>
  [key: string]: any
}

type FormContextReturnType = ReturnType<typeof useFormContext> & {
  classNames?: Record<'form' | 'field' | 'label' | 'input' | 'description' | 'error', string>
}

const FormField = 
  ({ name, label, type, description, children, required, rules, className, classNames, ...restProps }: FormFieldProps) => {
  let methods = null
  try {
    methods = useFormContext() as FormContextReturnType
  } catch {
    return <Button variant={"destructive"}>FormField must be used within a Form.</Button>
  }

  const ui = useFieldUIStateValue(name)
  const ContorlComponent = type && fieldMap[type] || Input
  const fieldId = `form-rhf-${name}` + (Math.random().toString(36).substring(2, 9))
  const formClassNames = methods?.classNames

  return ui.visible ? (
    <Controller
        name={name}
        control={methods?.control}
        rules={{ required, ...rules }}
        render={({ field, fieldState }) => (
        <Field data-invalid={fieldState.invalid} 
          className={cn(className, formClassNames?.field, classNames?.field)}>
          { label && <FieldLabel htmlFor={fieldId} className={cn(formClassNames?.label, classNames?.label)}>
            {label}{required && <span className="text-red-500">*</span>}
          </FieldLabel>}
          {
            children ? ( typeof children === 'function' ? children({
              id: fieldId,
              ...field,
              ...restProps,
              className: cn(formClassNames?.input, classNames?.input),
              'aria-invalid': fieldState.invalid
            }) : cloneElement(children as React.ReactElement<any>, {
              id: fieldId,
              ...field,
              ...restProps,
              className: cn(formClassNames?.input, classNames?.input),
              'aria-invalid': fieldState.invalid
            }) ) : (
              <ContorlComponent
                id={fieldId}
                {...field}
                {...restProps}
                className={cn(formClassNames?.input, classNames?.input)}
                aria-invalid={fieldState.invalid}
              />
            )
          }
          {description && (
            <FieldDescription className={cn(formClassNames?.description, classNames?.description)}>
              {description}
            </FieldDescription>
          )}
          {fieldState.invalid && (
            <FieldError errors={[fieldState.error]} className={cn(formClassNames?.error, classNames?.error)} />
          )}
        </Field>
      )}
    />
  ) : null
}

export default FormField

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"
import {
  InputGroup,
  InputGroupAddon,
  InputGroupInput,
  InputGroupTextarea
} from "@/components/ui/input-group"

const inputVariants = cva(
  "relative border transition-colors flex items-center",
  {
    variants: {
      variant: {
        default: "border-border bg-background",
        outline: "border-2 border-primary",
        filled: "border-primary/20 bg-primary/5",
        ghost: "border-transparent hover:bg-accent/50",
      },
      size: {
        sm: "h-8 text-sm",
        md: "h-10 text-base",
        lg: "h-12 text-lg",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "md",
    },
  }
)

export interface InputProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, "onChange" | "onBlur" | "onFocus" | "onInput" | "prefix">,
    VariantProps<typeof inputVariants> {
  /**
   * 输入框类型
   */
  inputType?: "input" | "textarea"
  /**
   * 当前值
   */
  value?: string
  /**
   * 默认值
   */
  defaultValue?: string
  /**
   * 占位提示
   */
  placeholder?: string
  /**
   * 是否禁用
   */
  disabled?: boolean
  /**
   * 是否只读
   */
  readOnly?: boolean
  /**
   * 是否显示清除按钮
   */
  allowClear?: boolean
  /**
   * 是否显示边框
   */
  bordered?: boolean
  /**
   * 最大长度
   */
  maxLength?: number
  /**
   * 前缀
   */
  prefix?: React.ReactNode
  /**
   * 后缀
   */
  suffix?: React.ReactNode
  /**
   * 前置标签
   */
  addonBefore?: React.ReactNode
  /**
   * 后置标签
   */
  addonAfter?: React.ReactNode
  /**
   * 是否展示字数统计
   */
  showCount?: boolean
  /**
   * 自动聚焦
   */
  autoFocus?: boolean
  /**
   * 值变化回调
   */
  onChange?: (value: string, event: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => void
  /**
   * 回车回调
   */
  onPressEnter?: (event: React.KeyboardEvent<HTMLInputElement>) => void
  /**
   * 失焦回调
   */
  onBlur?: (event: React.FocusEvent<HTMLInputElement | HTMLTextAreaElement>) => void
  /**
   * 聚焦回调
   */
  onFocus?: (event: React.FocusEvent<HTMLInputElement | HTMLTextAreaElement>) => void
  /**
   * 输入回调
   */
  onInput?: (event: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => void
  /**
   * 单元格键值
   */
  cellKey?: string
}

const FormInput = React.forwardRef<HTMLDivElement, InputProps>(
  (
    {
      className,
      inputType = "input",
      value: controlledValue,
      defaultValue = "",
      placeholder = "请输入内容",
      disabled = false,
      readOnly = false,
      allowClear = false,
      bordered = true,
      maxLength,
      prefix,
      suffix,
      addonBefore,
      addonAfter,
      showCount = false,
      autoFocus = false,
      onChange,
      onPressEnter,
      onBlur,
      onFocus,
      onInput,
      variant,
      size,
      cellKey,
      style,
      ...props
    },
    ref
  ) => {
    const [internalValue, setInternalValue] = React.useState(defaultValue)
    const isControlled = controlledValue !== undefined
    const value = isControlled ? controlledValue : internalValue

    const handleClear = React.useCallback(() => {
      const newValue = ""
      if (!isControlled) {
        setInternalValue(newValue)
      }
      const mockEvent = {
        target: { value: newValue },
      } as React.ChangeEvent<HTMLInputElement>
      onChange?.(newValue, mockEvent)
    }, [isControlled, onChange])

    const handleChange = React.useCallback(
      (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        const newValue = e.target.value ?? e
        if (!isControlled) {
          setInternalValue(newValue)
        }
        onChange?.(newValue, e)
      },
      [isControlled, onChange]
    )

    const handleKeyDown = React.useCallback(
      (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === "Enter") {
          onPressEnter?.(e)
        }
      },
      [onPressEnter]
    )

    const handleInput = React.useCallback(
      (e: React.FormEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        onInput?.(e as React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>)
      },
      [onInput]
    )

    const length = value?.length ?? 0
    const isMaxLengthReached = maxLength !== undefined && length >= maxLength

    // 多行输入框
    if (inputType === "textarea") {
      return (
        <InputGroup
          ref={ref}
          className={cn(!bordered && "border-0", inputVariants({ variant }), className)}
          style={style}
          {...props}
        >
          <InputGroupTextarea
            value={value}
            placeholder={placeholder}
            disabled={disabled}
            readOnly={readOnly}
            maxLength={maxLength}
            onChange={handleChange}
            onBlur={onBlur}
            onFocus={onFocus}
            onInput={handleInput}
            autoFocus={autoFocus}
            aria-invalid={props['aria-invalid']}
          />
          {allowClear && value && (
            <button
              type="button"
              onClick={handleClear}
              className="hover:text-foreground transition-colors p-2"
              disabled={disabled || readOnly}
            >
              <svg
                xmlns="http://www.w3.org/2000/svg"
                width="14"
                height="14"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
              >
                <circle cx="12" cy="12" r="10" />
                <path d="m15 9-6 6" />
                <path d="m9 9 6 6" />
              </svg>
            </button>
          )}
          {showCount && (
            <div className="absolute bottom-2 right-2 text-xs text-muted-foreground">
              <span>{length}</span>
              {maxLength && `/${maxLength}`}
            </div>
          )}
        </InputGroup>
      )
    }

    // 单行输入框
    return (
      <InputGroup
        ref={ref}
        className={cn(!bordered && "border-0", inputVariants({ variant, size }), className)}
        style={style}
      >
        {addonBefore && (
          <InputGroupAddon align="inline-start">
            {addonBefore}
          </InputGroupAddon>
        )}
        {prefix && (
          <InputGroupAddon align="inline-start">
            {prefix}
          </InputGroupAddon>
        )}
        <InputGroupInput
          value={value}
          placeholder={placeholder}
          disabled={disabled}
          readOnly={readOnly}
          maxLength={maxLength}
          onChange={handleChange}
          onKeyDown={handleKeyDown}
          onBlur={onBlur}
          onFocus={onFocus}
          onInput={handleInput}
          autoFocus={autoFocus}
          type="text"
          className="focus-visible:ring-ring focus-visible:ring-offset-0"
          {...props}
        />
        {allowClear && value && !disabled && !readOnly && (
          <button
            type="button"
            onClick={handleClear}
            className="hover:text-foreground text-muted-foreground transition-colors p-2"
          >
            <svg
              xmlns="http://www.w3.org/2000/svg"
              width="14"
              height="14"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            >
              <circle cx="12" cy="12" r="10" />
              <path d="m15 9-6 6" />
              <path d="m9 9 6 6" />
            </svg>
          </button>
        )}
        {suffix && (
          <InputGroupAddon align="inline-end">
            {suffix}
          </InputGroupAddon>
        )}
        {addonAfter && (
          <InputGroupAddon align="inline-end">
            {addonAfter}
          </InputGroupAddon>
        )}
        {isMaxLengthReached && (
          <div className="absolute right-3 text-xs text-destructive">
            <span>{length}/{maxLength}</span>
          </div>
        )}
      </InputGroup>
    )
  }
)
