}

// JSON 解析辅助函数
const parseJsonProp = (val: any, defaultVal: any = null) => {
    if (val === null || val === undefined) {
        return defaultVal
    }
    if (typeof val === 'string') {
        try {
            return JSON.parse(val)
        } catch {
            return defaultVal
        }
    }
    return val
}

// getPointMarkerSubProps - 获取数据点标记需要订阅的数据点
const getPointMarkerSubProps = (record: any, tableGisConfig: any, tableTags?: any[]) => {
    const { lat, lon, direction, course, velocity, rideHeight } = tableGisConfig || {}
    const tableId = record?._table || record?.tableId || record?.table
    // 基础的经纬度
    const baseTags = [
        { tableId, id: record.id, tagId: lat, type: 'lat' },
        { tableId, id: record.id, tagId: lon, type: 'lon' },
    ]
    // 表配置的额外数据点
    const optionalTags = [
        direction && { tableId, id: record.id, tagId: direction, type: 'direction' },
        velocity && { tableId, id: record.id, tagId: velocity, type: 'velocity' },
        rideHeight && { tableId, id: record.id, tagId: rideHeight, type: 'rideHeight' },
        course && { tableId, id: record.id, tagId: course, type: 'course' }
    ].filter(Boolean)
    // 图层选择额外订阅的数据
    const tableSelectTags = tableTags?.map((tagId: any) => {
        const hassub = [lat, lon, direction, course, velocity, rideHeight].indexOf(tagId) >= 0
        if (hassub) {
            return null
        } else {
            return { tableId, id: record.id, tagId }
        }
    }).filter(Boolean)
    return [...baseTags, ...optionalTags, ...(tableSelectTags || [])]
}

const TableViews = React.forwardRef<HTMLDivElement, TableViewsProps>(
    (
        {
            className,
            table: tableProp,
            tableData: tableDataProp,
            tableFilters: tableFiltersProp,
            department: departmentProp,
            getQueryFilter: getQueryFilterProp,
            tableTags: tableTagsProp,
            coordinateType,
            layerBase,
            heatmap,
            cluster,
            display = true,
            cellKey,
            map: mapProp,
            marker: markerProp,
            highlightMarker: highlightMarkerProp,
            markerScale: markerScaleProp,
            ...props
        },
        ref
    ) => {
        const contextMap = useMap()
        const map = mapProp || contextMap
        // ===== 数据解析和转换 =====
        // 解析 JSON 字符串参数
        const table = React.useMemo(() => parseJsonProp(tableProp, null), [tableProp])
        const tableData = React.useMemo(() => parseJsonProp(tableDataProp, []), [tableDataProp])
        const tableFilters = React.useMemo(() => parseJsonProp(tableFiltersProp, {}), [tableFiltersProp])
        const department = React.useMemo(() => parseJsonProp(departmentProp, null), [departmentProp])
        const getQueryFilter = React.useMemo(() => parseJsonProp(getQueryFilterProp, null), [getQueryFilterProp])
        const tableTags = React.useMemo(() => parseJsonProp(tableTagsProp, null), [tableTagsProp])
        const marker = React.useMemo(() => parseJsonProp(markerProp, {}), [markerProp])
        const highlightMarker = React.useMemo(() => parseJsonProp(highlightMarkerProp, {}), [highlightMarkerProp])
        const markerScale = React.useMemo(() => parseJsonProp(markerScaleProp, null), [markerScaleProp])

        // 判断数据源类型 - 完全对应 record.js 的逻辑
        const hasRecord = tableData?.length > 0  // 有表记录
        const hasTable = !!table?.id  // 有指定表（注意：table 是单个对象，不是数组）

        // 图层引用
        const layerRef = React.useRef<any[]>([])
        const sourceRef = React.useRef<any>(null)
        const pointSourceRef = React.useRef<any>(null)

        // 标记样式配置缓存
        const markerScaleRef = React.useRef<any>(null)
        const highlightRef = React.useRef<any>(null)

        // Request tracker for cancelling stale requests
        const requestTracker = React.useRef<any>(null)

        // 更新缓存标记配置
        React.useEffect(() => { markerScaleRef.current = markerScale }, [markerScale])
        React.useEffect(() => { highlightRef.current = highlightMarker }, [highlightMarker])

        // 样式函数
        const styleFn = React.useCallback((feature: any) => {
            const record = feature.get('record')
            const tableGisConfig = feature.get('tableGisConfig')
            const selected = feature.get('selected')
            const markerTags = feature.get('markerTags')
            const markerType = feature.get('markerType') || 'Point'  // 从 feature 获取，不是从配置
            const markerInitStyle = feature.get('markerInitStyle')
            const online = record?.online !== false

            // Merge marker configs
            let mergedMarker = { ...marker }
            if (tableGisConfig?.Point) {
                mergedMarker = _.merge({}, mergedMarker, { point: tableGisConfig.Point })
            }

            let mergedHighlight = { ...highlightMarker }
            const currentMarker = selected ? mergedHighlight : mergedMarker

            const iconScript = currentMarker?.point?.iconScript
            const visible = currentMarker?.point?.visible !== false

            if (!visible) return []

            // Determine icon source (使用默认图标)
            let src = markerInitStyle?.src || markerInitStyle?.icon || DEFAULT_MARKER_ICON

            // 图标脚本处理
            if (iconScript) {
                const parsedSrc = parseIconScript({
                    iconScript,
                    record,
                    tags: markerTags,
                    style: olStyle
                })
                if (parsedSrc) src = parsedSrc
            }
            // 在线/离线图标处理
            else if (markerInitStyle?.onlineIcon && markerInitStyle?.iconUrl) {
                src = online ? markerInitStyle.onlineIcon : markerInitStyle.iconUrl
            }

            // Apply scale
            let scale = markerInitStyle?.scale || 1
            if (markerScaleRef.current?.length) {
                const view = map?.getView()
                if (view) {
                    const zoom = view.getZoom() || 0
                    for (const s of markerScaleRef.current) {
                        if (s.minZoom <= zoom && zoom <= s.maxZoom) {
                            scale = s.scale
                            break
                        }
                    }
                }
            }

            // Rotation handling
            let rotation = 0
            if (markerTags) {
                const direction = markerTags.direction || markerTags.course
                if (typeof direction === 'number') {
                    rotation = direction * (Math.PI / 180)
                }
            }

            const styleConfig = {
                ...markerInitStyle,
                icon: {
                    ...markerInitStyle?.icon,
                    iconSrc: src,
                    scale,
                    rotation,
                    rotateWithView: !!rotation
                }
            }

            return createStyleClass({
                markerType,
                style: styleConfig,
                zIndex: selected ? 9 : 0,
                zoomScale: scale
            })
        }, [marker, highlightMarker, map])

        // 聚合样式函数
        const styleClusterFn = React.useCallback((feature: any) => {
            const features = feature.get('features')
            const size = features?.length
            if (size == 1) {
                return styleFn(features[0])
            } else {
                return clusterStyle(cluster || {}, size)
            }
        }, [cluster, styleFn])

        // 数据查询主逻辑 - 完全对应 record.js 的三种模式
        const loadData = React.useCallback(async () => {

            try {
                let result: any = null

                // 模式 1: queryRecordInit - 有表记录数据
                if (hasRecord) {

                    // 提取所有涉及的表ID
                    const tableIds = new Set<string>()
                    tableData.forEach((r: any) => {
                        // 支持多种格式：_table, tableId, table.id, table
                        const tid = r._table || r.tableId || r.table?.id || (typeof r.table === 'string' ? r.table : null)
                        if (tid) tableIds.add(tid)
                    })
                    const uniqueTableIds = Array.from(tableIds)

                    if (uniqueTableIds.length === 0) {
                        return { features: [], tableRecords: [] }
                    }

                    // 获取表配置
                    const tableList = await getGISTable(uniqueTableIds)
                    const tableMap = _.keyBy(tableList, 'id')

                    // 按表分组数据
                    const dataByTable: Record<string, any[]> = {}
                    tableData.forEach((r: any) => {
                        const tid = r._table || r.tableId || r.table?.id
                        if (tid && tableMap[tid]) {
                            if (!dataByTable[tid]) dataByTable[tid] = []
                            dataByTable[tid].push(r)
                        }
                    })

                    // 使用 getReord 逐个查询完整记录（与 record.js 一致）
                    let features: any[] = []
                    const tableRecordObj: Record<string, any> = {}

                    for (const r of tableData) {
                        const tableId = r._table || r.tableId || r.table?.id || (typeof r.table === 'string' ? r.table : null)

                        if (!tableId || !tableMap[tableId]) {
                            continue
                        }

                        if (!r.id) {
                            continue
                        }

                        // 重新查询完整记录
                        const record = await getReord(tableId, r.id)
                        const tableGisConfig = tableMap[tableId]?.gis

                        // 按表分组记录
                        if (tableRecordObj[tableId]) {
                            tableRecordObj[tableId].record.push(record)
                        } else {
                            tableRecordObj[tableId] = {
                                gis: tableGisConfig,
                                tableId,
                                record: [record]
                            }
                        }

                        // 生成 features
                        const recordFeatures = await generateTableMarker([record], tableGisConfig, coordinateType, tableTags)
                        features = features.concat(recordFeatures)
                    }

                    const tableRecords = Object.values(tableRecordObj)
                    result = { features, featureslist: [features], tableRecords }
                }
                // 模式 2: queryTableAndRecordInit - 有指定表（单个表对象）
                else if (hasTable) {

                    // 获取指定表的配置
                    const tableList = await getGISTable([table.id])

                    if (tableList.length === 0) {
                        return { features: [], tableRecords: [] }
                    }

                    const tableConfig = tableList[0]

                    if (!tableConfig.gis || _.isEmpty(tableConfig.gis)) {
                        return { features: [], tableRecords: [] }
                    }

                    let rfilter: any = {}

                    // 应用部门过滤
                    if (department && department.length > 0) {
                        const tableDepartmentFilter = await getTableDepartmentFilter([table.id], department)
                        const filter = _.omit(tableDepartmentFilter[table.id], 'NoDepart')
                        if (tableDepartmentFilter[table.id]?.NoDepart) {
                            // 该表不可访问
                            return { features: [], tableRecords: [] }
                        }
                        rfilter = filter
                    }

                    // 应用查询过滤器
                    if (tableFilters && !_.isEmpty(tableFilters)) {
                        const tableFilterObj = getQueryFilter ? getQueryFilter(tableFilters, tableConfig.schema) : tableFilters
                        rfilter = { ...rfilter, ...tableFilterObj }
                    }


                    // 查询记录
                    const tableRecord = await getTableRecord(tableConfig, rfilter)

                    if (!tableRecord || !tableRecord.record) {
                        return { features: [], tableRecords: [] }
                    }

                    // 生成 features
                    const features = await generateTableMarker(
                        tableRecord.record,
                        tableRecord.gis,
                        coordinateType,
                        tableTags
                    )

                    result = {
                        features,
                        featureslist: [features],
                        tableRecords: [tableRecord]
                    }
                }
                // 模式 3: queryAllTableAndDataInit - 查询所有GIS表
                else {

                    // 获取所有GIS表
                    const tableList = await getGISTable()

                    // 过滤有效的GIS表
                    let tableListAvailable = tableList.filter((t: any) => {
                        const gis = t?.gis
                        const mapping = gis?.mapping
                        if (!mapping || t.id === "普通表地理信息") return false
                        const p1 = mapping === 'dataPoint' && gis.lat && gis.lon
                        const p2 = mapping === 'map' && gis.map
                        const p3 = mapping === 'noLimit'
                        return p1 || p2 || p3
                    })

                    if (tableListAvailable.length === 0) {
                        return { features: [], tableRecords: [] }
                    }

                    // 应用部门过滤
                    let departmentFilters: Record<string, any> = {}
                    if (department && department.length > 0) {
                        const tableids = tableListAvailable.map((t: any) => t.id)
                        departmentFilters = await getTableDepartmentFilter(tableids, department)

                        // 过滤掉 NoDepart 的表
                        tableListAvailable = tableListAvailable.filter((t: any) => {
                            return !departmentFilters[t.id]?.NoDepart
                        })
                    }

                    // 并发查询所有表的记录
                    const promiseFns: Promise<any>[] = []
                    tableListAvailable.forEach((t: any) => {
                        let filter = {}
                        if (department && department.length > 0 && departmentFilters[t.id]) {
                            filter = _.omit(departmentFilters[t.id], 'NoDepart')
                        }
                        promiseFns.push(getTableRecord(t, filter))
                    })

                    const tableRecords = await Promise.all(promiseFns)

                    // 生成 features
                    const featureslist: any[] = []
                    for (const element of tableRecords) {
                        const features = await generateTableMarker(
                            element.record,
                            element.gis,
                            coordinateType,
                            tableTags
                        )
                        featureslist.push(features)
                    }

                    result = {
                        features: featureslist.flat(),
                        featureslist,
                        tableRecords
                    }
                }

                return result || { features: [], tableRecords: [] }

            } catch (e) {
                return { features: [], tableRecords: [] }
            }

        }, [hasRecord, hasTable, table, tableData, coordinateType, tableFilters, department, getQueryFilter, tableTags])

        // generateTableMarker - 生成表标记
        const generateTableMarker = async (
            recordList: any[],
            tableGisConfig: any,
            coordinateType?: string,
            tableTags?: any
        ) => {

            const allFeatures: any[] = []
            const mapping = tableGisConfig?.mapping

            if (!mapping) {
                return allFeatures
            }

            if (mapping === 'dataPoint') {
                const subTags = recordList.flatMap((t: any) => getPointMarkerSubProps(t, tableGisConfig, tableTags))

                if (subTags.length > 0) {
                    const dataPoints = await getTableRecordDataPoint(subTags)
                    const dataMap = _.keyBy(dataPoints, (d: any) => `${d.id}`)

                    recordList.forEach((r: any) => {
                        const dpLat = dataMap[r.id]?.[tableGisConfig.lat]
                        const dpLon = dataMap[r.id]?.[tableGisConfig.lon]

                        if (dpLat && dpLon) {
                            const f = createFeature({
                                type: 'Point',
                                record: r,
                                coordinate: [dpLon, dpLat],
                                style: tableGisConfig.Point,
                                coordinateType,
                                markerTags: dataMap[r.id],
                                cellKey,
                                tableGisConfig
                            })
                            allFeatures.push(f)
                        }
                    })
                }

            } else if (mapping === 'map') {
                const mapField = tableGisConfig.map
                recordList.forEach((r: any) => {
                    const loc = r[mapField]
                    if (loc && loc.lng && loc.lat) {
                        const f = createFeature({
                            type: 'Point',
                            record: r,
                            coordinate: [loc.lng, loc.lat],
                            style: tableGisConfig.Point,
                            coordinateType,
                            cellKey,
                            tableGisConfig
                        })
                        allFeatures.push(f)
                    }
                })
            } else if (mapping === 'noLimit') {
                recordList.forEach((r: any) => {
                    const gisSource = r._settings?.gis

                    if (gisSource?.location?.data) {
                        gisSource.location.data.forEach((d: any) => {
                            let mergedStyle = { ...tableGisConfig[d.type] }
                            if (gisSource.location.geometryStyle) {
                                mergedStyle = _.merge({}, mergedStyle, gisSource.location.geometryStyle)
                            }
                            if (d.style) {
                                mergedStyle = _.merge({}, mergedStyle, d.style)
                            }

                            const f = createFeature({
                                type: d.type,
                                record: r,
                                coordinate: d.coordinates,
                                style: mergedStyle,
                                coordinateType,
                                cellKey,
                                tableGisConfig
                            })

                            allFeatures.push(f)
                        })
                    } else {
                        const emptyFeature = createEmptyFeature(r)
                        allFeatures.push(emptyFeature)
                    }
                })
            }

            return allFeatures
        }

        // 防抖数据初始化
        const debouncedInit = React.useMemo(() => _.debounce(async () => {
            if (!map) return
            const source = sourceRef.current
            if (!source) return

            // 清除现有数据
            source.clear()

            const currentRequest = Symbol('currentRequest')
            requestTracker.current = currentRequest

            try {
                const result = await loadData()

                if (requestTracker.current === currentRequest) {
                    if (result?.features && result.features.length > 0) {
                        result.features.forEach((f: any) => f.set('cellKey', cellKey))
                        source.addFeatures(result.features)
                    } else {
                    }
                }
            } catch (error) {
                if (requestTracker.current === currentRequest) {
                }
            }

        }, DEBOUNCE_DELAY), [
            map,
            loadData,
            hasRecord,
            hasTable,
            table?.id,
            Array.isArray(department) ? department.map((d: any) => d?.id).join() : '',
            Array.isArray(tableData) ? tableData.map((d: any) => d?.id).join() : '',
            JSON.stringify(tableFilters)
        ])

        // 地图数据初始化
        React.useEffect(() => {
            debouncedInit()
            return () => {
                debouncedInit.cancel()
                requestTracker.current = null
            }
        }, [debouncedInit])

        // 初始化地图层
        React.useEffect(() => {
            if (!map) return

            const { opacity, zIndex, maxResolution, minResolution, maxZoom, minZoom } = layerBase || {}

            // 基础数据source
            const baseSource = new VectorSource({ features: [] })
            const nonPointSource = new VectorSource({ features: [] })
            const pointSource = new VectorSource({ features: [] })

            sourceRef.current = baseSource
            pointSourceRef.current = pointSource

            // 注册 pointSource 到 map
            if (cellKey) {
                try {
                    map.set(`gisv2.record.pointSource:${cellKey}`, pointSource)
                } catch (e) {
                    console.error(e)
                }
            }

            // baseSource添加feature时，自动分发到点/非点source
            baseSource.on('addfeature', (e: any) => {
                const targetFeature = e.feature
                const type = targetFeature.getGeometry()?.getType()
                if (type === 'Point') {
                    pointSource.addFeature(targetFeature)
                } else {
                    nonPointSource.addFeature(targetFeature)
                }
            })

            baseSource.on('removefeature', (e: any) => {
                const feature = e.feature
                const type = feature?.getGeometry()?.getType()
                if (type === 'Point') {
                    pointSource.removeFeature(feature)
                } else {
                    nonPointSource.removeFeature(feature)
                }
            })

            baseSource.on('clear', () => {
                nonPointSource.clear()
                pointSource.clear()
            })

            // 创建点图层
            const createPointsLayer = () => {
                const layerlist = []
                const layerconfig = {
                    opacity,
                    zIndex,
                    maxResolution,
                    minResolution,
                    maxZoom,
                    minZoom,
                }

                if (cluster?.show) {
                    const clusterSource = new Cluster({
                        distance: cluster.distance || 20,
                        minDistance: cluster.minDistance || 10,
                        source: pointSource
                    })
                    const clusterLayer = new VectorLayer({
                        source: clusterSource,
                        id: 'cluster_' + cellKey,
                        layerType: 'cluster',
                        style: styleClusterFn,
                        ...layerconfig
                    })
                    layerlist.push(clusterLayer)
                }
                if (heatmap?.show) {
                    const heatmapLayer = new Heatmap({
                        source: pointSource,
                        id: 'heatmap_' + cellKey,
                        layerType: 'heatmap',
                        blur: heatmap?.blur || 15,
                        radius: heatmap?.radius || 8,
                        gradient: createHeatmapGradient(heatmap?.gradient || []),
                        zIndex: 888
                    })
                    layerlist.push(heatmapLayer)
                }
                if (!cluster?.show && !heatmap?.show) {
                    const layer = new VectorLayer({
                        source: pointSource,
                        id: cellKey,
                        layerType: 'default',
                        style: styleFn,
                        properties: { layerType: 'table', cellKey },
                        ...layerconfig
                    })
                    layerlist.push(layer)
                }
                return layerlist.filter(Boolean)
            }

            const pointsLayerList = createPointsLayer()
            pointsLayerList.forEach((l: any) => map.addLayer(l))

            const nonPointLayer = new VectorLayer({
                source: nonPointSource,
                id: cellKey,
                style: styleFn,
                layerType: 'base',
                opacity,
                zIndex,
                maxResolution,
                minResolution,
                maxZoom,
                minZoom,
            })
            map.addLayer(nonPointLayer)
            layerRef.current = [nonPointLayer, ...pointsLayerList]

            return () => {
                if (cellKey && map.unset) {
                    try { map.unset(`gisv2.record.pointSource:${cellKey}`) } catch (e) { }
                }
                if (map && layerRef.current) {
                    layerRef.current.forEach((l: any) => {
                        map.removeLayer(l)
                    })
                }
            }
        }, [map?.ol_uid])

        // Visibility
        React.useEffect(() => {
            if (!layerRef.current) return
            layerRef.current.forEach((l: any) => l.setVisible(display))
        }, [display])

        // 在挂载后修改配置项更新地图标记点
        React.useEffect(() => {
            if (layerRef.current.length > 0) {
                layerRef.current.forEach((l: any) => {
                    const isClusterLayer = l?.get('layerType') == 'cluster'
                    if (isClusterLayer) {
                        l.setStyle(styleClusterFn)
                    } else {
                        l.setStyle(styleFn)
                    }
                })
            }
        }, [
            cluster?.text,
            cluster?.radius,
            cluster?.color,
            cluster?.font,
            cluster?.background,
            JSON.stringify(marker)
        ])

        // 聚合配置更新
        React.useEffect(() => {
            const clusterLayer = layerRef.current.find((l: any) => l?.get('layerType') == 'cluster')
            const clusterSource = clusterLayer?.getSource()
            if (clusterSource) {
                cluster?.distance && clusterSource.setDistance(cluster.distance || 20)
                cluster?.minDistance && clusterSource.setMinDistance(cluster.minDistance || 10)
            }
        }, [
            cluster?.distance,
            cluster?.minDistance,
        ])

        // 热力图配置更新
        React.useEffect(() => {
            const heatmapLayer = layerRef.current.find((l: any) => l?.get('layerType') == 'heatmap')
            if (heatmapLayer) {
                heatmap?.blur && heatmapLayer.setBlur(heatmap.blur)
                heatmap?.gradient && heatmapLayer.setGradient(createHeatmapGradient(heatmap.gradient))
                heatmap?.radius && heatmapLayer.setRadius(heatmap.radius)
            }
        }, [
            heatmap?.gradient,
            heatmap?.radius,
            heatmap?.blur
        ])

        // 热力图和聚合显示隐藏时更新layer
        React.useEffect(() => {
            if (!map) return
            let nonPointLayer
            layerRef.current?.forEach((layer: any) => {
                if (!layer) return
                const layerType = layer.get('layerType')
                if (!layerType) { nonPointLayer = layer }
                if (layerType == 'heatmap' || layerType == 'cluster' || layerType == 'default') {
                    map.removeLayer(layer)
                }
            })

            const { opacity, zIndex, maxResolution, minResolution, maxZoom, minZoom } = layerBase || {}
            const layerconfig = {
                opacity,
                zIndex,
                maxResolution,
                minResolution,
                maxZoom,
                minZoom,
            }

            const createPointsLayer = () => {
                const layerlist = []
                if (cluster?.show) {
                    const clusterSource = new Cluster({
                        distance: cluster.distance || 20,
                        minDistance: cluster.minDistance || 10,
                        source: pointSourceRef.current
                    })
                    const clusterLayer = new VectorLayer({
                        source: clusterSource,
                        id: 'cluster_' + cellKey,
                        layerType: 'cluster',
                        style: styleClusterFn,
                        ...layerconfig
                    })
                    layerlist.push(clusterLayer)
                }
                if (heatmap?.show) {
                    const heatmapLayer = new Heatmap({
                        source: pointSourceRef.current,
                        id: 'heatmap_' + cellKey,
                        layerType: 'heatmap',
                        blur: heatmap?.blur || 15,
                        radius: heatmap?.radius || 8,
                        gradient: createHeatmapGradient(heatmap?.gradient || []),
                        zIndex: 888
                    })
                    layerlist.push(heatmapLayer)
                }
                if (!cluster?.show && !heatmap?.show) {
                    const layer = new VectorLayer({
                        source: pointSourceRef.current,
                        id: cellKey,
                        layerType: 'default',
                        style: styleFn,
                        ...layerconfig
                    })
                    layerlist.push(layer)
                }
                return layerlist.filter(Boolean)
            }

            const pointsLayerList = createPointsLayer()
            pointsLayerList.forEach((l: any) => map.addLayer(l))
            layerRef.current = [nonPointLayer, ...pointsLayerList]
        }, [cluster?.show, heatmap?.show])

        const { modalConfig, selectConfig, ...restProps } = props

        return (
            <div
                ref={ref}
                className={cn("table-views", className)}
                style={{ display: 'none' }}
                data-cell-key={cellKey}
                {...restProps}
            />
        )
    }
)

TableViews.displayName = "TableViews"

export { TableViews }

import Feature from 'ol/Feature'
import * as geom from 'ol/geom'
import * as style from 'ol/style'
import { fromLonLat } from 'ol/proj'
import _ from 'lodash'

// 简化的 mapMaxResolution
const mapMaxResolution = 156543.03392804097;

export const getMapZoomforResolution = (resolution: number) => {
    return Math.log(mapMaxResolution / resolution) / Math.LN2;
}

export const getMarkerId = (record: any) => {
    return (record?.table || record?._table || record.tableId) + '|' + record?.id
}

// 简单的坐标转换，默认 EPSG:4326 -> EPSG:3857
export const getTransformTo3857 = (coordinateType?: string) => {
    // 暂时忽略 coordinateType 的复杂判断，假设输入是 WGS84，输出 3857
    // 如果需要支持其他坐标系，这里需要 proj4
    return (coordinate: number[]) => fromLonLat(coordinate)
}

export const generateHalfCircle = (center: number[], radius: number, startAngle: number, endAngle: number) => {
    const angleStep = Math.PI / 180;
    const offset = 180
    let points = [];
    for (let angle = Math.PI * ((startAngle - offset) / (180)); angle <= Math.PI * ((endAngle - offset) / 180); angle += angleStep) {
        points.push([
            center[0] + Math.cos(angle) * radius,
            center[1] - Math.sin(angle) * radius  // Y 轴向下移动
        ])
    }
    return points
}

export const createFeature = ({ type, record, style: styleConfig, coordinate, coordinateType, markerTags, cellKey, tableGisConfig }: any) => {
    const transform = getTransformTo3857(coordinateType)
    let feature = new Feature({})

    if (!coordinate) return feature;

    if (type == 'Point') {
        feature = new Feature({
            geometry: new geom.Point(transform(coordinate)),
        });
    } else if (type == 'LineString') {
        feature = new Feature({
            geometry: new geom.LineString(coordinate.map((coord: number[]) => transform(coord)))
        })
    } else if (type == 'Polygon') {
        feature = new Feature({
            geometry: new geom.Polygon(coordinate.map((coord: number[][]) => coord.map(c => transform(c))))
        })
    } else if (type == 'Circle') {
        if (!coordinate?.center || !coordinate?.radius) return feature
        feature = new Feature({
            geometry: new geom.Circle(transform(coordinate.center), coordinate.radius),
        })
    } else if (type == 'Semicircle') {
        const { center, radius } = coordinate
        const { isClose, startAngle = 0, endAngle = 180 } = styleConfig || {}
        const transCenter = transform(center)
        const geo = generateHalfCircle(transCenter, radius, startAngle, endAngle)
        let geometry: geom.Geometry = new geom.LineString(geo)
        if (isClose) {
            geo.push(transCenter)
            geo.push(geo[0])
            geometry = new geom.Polygon([geo])
        }
        feature = new Feature({ geometry });
    }

    feature.setId(getMarkerId(record))
    feature.setProperties({
        markerRecord: record,
        markerType: type,
        markerInitStyle: styleConfig,
        markerTags: markerTags,
        markerLabel: record._label,
        cellKey,
        tableGisConfig
    }, true)
    return feature
}

export const createEmptyFeature = (record: any) => {
    let feature = new Feature({})
    feature.setId(getMarkerId(record))
    feature.setProperties({
        markerRecord: record,
        markerLabel: record._label,
    }, true)
    return feature
}

export function isInRange(current: number, min: number | null, max: number | null) {
    if (min === null && max === null) {
        return false;
    }
    const minValid = min === null || current >= min;
    const maxValid = max === null || current <= max;
    return minValid && maxValid;
}

export function clusterStyle(cluster: any, size: number) {
    return new style.Style({
        image: new style.Circle({
            radius: cluster?.radius || 18,
            fill: new style.Fill({
                color: cluster?.background || 'rgba(0, 0, 255, 0.6)'
            })
        }),
        text: new style.Text({
            font: `${cluster.font || 15}px sans-serif`,
            text: cluster?.text ? cluster?.text.indexOf('XX') > -1 ? cluster?.text?.replace('XX', size?.toString()) : cluster?.text : size?.toString(),
            fill: new style.Fill({
                color: cluster?.color || '#fff'
            })
        })
    })
}

export function parseIconScript({ iconScript, record, tags, style }: any) {
    if (!iconScript || typeof iconScript !== 'string') {
        return null;
    }
    try {
        // eslint-disable-next-line @typescript-eslint/no-implied-eval
        const scriptFn = new Function('record', 'tags', 'style', `
      try {
        const userFn = ${iconScript};
        return typeof userFn === 'function' ? userFn(record, tags, style) : null;
      } catch (e) {
        return null;
      }
    `);
        let result = scriptFn(record, tags, style)
        if (_.isString(result)) {
            // 假设 /rest 开头是相对路径，否则补上前缀（这里简化处理，直接返回）
            // result = result.startsWith('/rest') ? result : config('mediaUrl') + result
        }
        return result
    } catch (error) {
        console.error('图标脚本解析失败:', error);
        return null;
    }
}

export const createNumberLabelStyles = ({ geometry, baseStyle, textStyle = {} }: any) => {
    if (!geometry) {
        return baseStyle
    }

    const geoType = geometry.getType()
    let coordinates: number[][] = []

    if (geoType === 'LineString') {
        coordinates = (geometry as geom.LineString).getCoordinates() || []
    } else if (geoType === 'Polygon') {
        const rings = (geometry as geom.Polygon).getCoordinates() || []
        if (rings.length > 0) {
            coordinates = rings[0] || []
        }
    }

    if (!coordinates || coordinates.length === 0) {
        return baseStyle
    }

    // 如果是闭合多边形，去掉最后一个重复的点
    if (coordinates.length > 1) {
        const first = coordinates[0]
        const last = coordinates[coordinates.length - 1]
        if (first && last && first[0] === last[0] && first[1] === last[1]) {
            coordinates = coordinates.slice(0, coordinates.length - 1)
        }
    }

    // 默认文本样式
    const defaultTextStyle = {
        font: '12px Calibri,sans-serif',
        fillColor: '#000000',
        strokeColor: '#ffffff',
        strokeWidth: 2,
        offsetY: -12,
        ...textStyle
    }

    // 创建序号标签样式
    const labelStyles = coordinates.map((coord, index) => new style.Style({
        geometry: new geom.Point(coord),
        text: new style.Text({
            text: String(index + 1),
            font: defaultTextStyle.font,
            fill: new style.Fill({ color: defaultTextStyle.fillColor }),
            stroke: new style.Stroke({ color: defaultTextStyle.strokeColor, width: defaultTextStyle.strokeWidth }),
            offsetY: defaultTextStyle.offsetY,
        })
    }))

    return [baseStyle, ...labelStyles]
};


// 样式创建相关
const defaultIcon = 'https://ui.shadcn.com/avatars/01.png' // 临时默认图标

export const createIconClass = ({ iconSrc, color, offsetX, offsetY, scale, rotation, displacementX, displacementY, rotateWithView }: any, zoomScale: any) => {

    const baseScale = scale ? scale : 1
    let normalizedSrc = iconSrc
    if (typeof normalizedSrc === 'string' && normalizedSrc) {
        try {
            normalizedSrc = encodeURI(normalizedSrc)
        } catch (e) {
            normalizedSrc = iconSrc
        }
    }

    const iconOptions: any = {
        src: normalizedSrc || defaultIcon,
        offset: [offsetX || 0, offsetY || 0],
        scale: zoomScale ? zoomScale * baseScale : baseScale,
        anchor: [0.5, 0.5],
        anchorXUnits: 'fraction',
        anchorYUnits: 'fraction',
        rotation: rotation || 0,
        rotateWithView: rotateWithView !== undefined ? rotateWithView : true,
        displacement: [displacementX || 0, displacementY || 0]
    }

    if (color) {
        iconOptions.color = color
    }

    return new style.Icon(iconOptions)
}

export const createTextClass = ({ text, font, fill, stroke, scale, rotation, offsetX, offsetY, backgroundFill }: any, zoomScale?: any) => {

    const baseScale = scale ? scale : 1

    return new style.Text({
        text: text || '',
        font: font || `12px Calibri,sans-serif`,
        fill: new style.Fill({ color: fill || 'rgba(0,0,0,1)' }),
        stroke: new style.Stroke({ color: stroke || 'rgba(255,255,255,1)', width: 2 }),
        scale: zoomScale ? zoomScale * baseScale : baseScale,
        rotation: rotation || 0,
        offsetX: offsetX || 0,
        offsetY: offsetY || 0,
        backgroundFill
    })
}

export const createStyleClass = ({
    markerType,
    style: markerStyle,
    zIndex,
    zoomScale
}: any) => {

    const {
        icon, line, polygon, circle, semicircle, text,
        textSetting, iconUrl, iconSetting, backgroundFill
    } = markerStyle || {}

    let iconStyle = icon || {}
    let textStyle = text || {}

    if (textSetting) { textStyle = _.merge(textSetting, textStyle) }
    if (backgroundFill && !textStyle.fill) { textStyle['fill'] = backgroundFill }

    if (markerType == 'Point') {
        if (iconUrl && !iconStyle?.iconSrc) {
            iconStyle.iconSrc = iconUrl || {}
        }
        if (iconSetting) {
            iconStyle = _.merge(iconSetting, iconStyle || {})
        }
        return new style.Style({
            image: createIconClass(iconStyle || {}, zoomScale),
            text: createTextClass(textStyle || {}, zoomScale),
            zIndex: zIndex || 0,
        })
    } else {
        // 简化处理线面圆的样式获取
        let typeStyle: any = {}
        if (markerType === 'LineString') typeStyle = line
        if (markerType === 'Polygon') typeStyle = polygon
        if (markerType === 'Circle') typeStyle = circle
        if (markerType === 'Semicircle') typeStyle = semicircle

        const { fill, color, width, lineDash } = typeStyle || {}

        let fillColor = fill
        let strokeColor = color
        let strokeWidth = width || 2
        let strokeLineDash = lineDash

        if (!fillColor) fillColor = markerStyle?.fillColor
        if (!strokeColor) strokeColor = markerStyle?.color
        if (!strokeWidth) strokeWidth = markerStyle?.width

        return new style.Style({
            text: createTextClass(textStyle || {}),
            zIndex: zIndex || 0,
            fill: fillColor && new style.Fill({ color: fillColor }),
            stroke: new style.Stroke({
                color: strokeColor,
                width: strokeWidth,
                lineDash: (strokeLineDash == "dashed" || strokeLineDash == 'dash') ? [10, 10] : null
            }),
        })
    }
}

export function getGeometryCenter(geometry: geom.Geometry) {
    const type = geometry.getType();

    switch (type) {
        case 'Point':
            return (geometry as geom.Point).getCoordinates();

        case 'LineString':
            const lineCoords = (geometry as geom.LineString).getCoordinates();
            const midIndex = Math.floor(lineCoords.length / 2);
            return lineCoords[midIndex];

        case 'Polygon':
            const interiorPoint = (geometry as geom.Polygon).getInteriorPoint().getCoordinates()
            return interiorPoint.slice(0, 2)

        case 'Circle':
            return (geometry as geom.Circle).getCenter();

        default:
            return null;
    }
}

import Map from 'ol/Map'
import * as proj from 'ol/proj'
import proj4 from 'proj4'
import { register } from 'ol/proj/proj4'

// 注册 proj4 到 OpenLayers
register(proj4)

// 坐标系映射表（兼容多种别名）
const COORD_SYSTEM_MAP: Record<string, string> = {
    // WGS84系列
    WGS84: 'EPSG:4326',
    WGS1984: 'EPSG:4326',
    EPSG4326: 'EPSG:4326',
    'EPSG:4326': 'EPSG:4326',

    // 火星坐标系
    GCJ02: 'GCJ02',
    AMap: 'GCJ02',

    // 百度坐标系
    BD09: 'BD09',
    BD09LL: 'BD09',
    Baidu: 'BD09',
    BMap: 'BD09',
    BD09MC: 'BD09MC',
    BD09Meter: 'BD09MC',

    // Web墨卡托
    EPSG3857: 'EPSG:3857',
    'EPSG:3857': 'EPSG:3857',
    EPSG900913: 'EPSG:3857',
    EPSG102100: 'EPSG:3857',
    WebMercator: 'EPSG:3857',
    WM: 'EPSG:3857'
}

export const getProjectionCode = (coordinateType: string) => {
    return COORD_SYSTEM_MAP[coordinateType] || coordinateType
}

// 获取地图坐标系类型
export const getMapCoordinateType = (map: Map | null) => {
    if (!map || !map.getView) {
        // 默认返回 EPSG:3857
        return 'EPSG:3857'
    }
    const view = map.getView();
    const projection = view.getProjection();
    const code = projection.getCode()
    return code
}

// 获取 Projection 对象
export const getProjection = (coorDefs: any, tileCoordinateType: string | undefined, mapCoordinateSystem: string) => {
    const dataProjection = coorDefs?.dataProjection
    // 如果没有提供坐标系定义，使用默认的地图坐标系（或 tileCoordinateType）
    const tileProjectionCode = dataProjection || tileCoordinateType || mapCoordinateSystem

    // 1. 标准坐标系处理
    if (['EPSG:4326', 'EPSG:3857'].includes(tileProjectionCode)) {
        return proj.get(tileProjectionCode);
    }

    // 2. 自定义坐标系处理 (Proj4)
    if (dataProjection && coorDefs?.defs) {
        // 注册自定义坐标系
        try {
            proj4.defs(dataProjection, coorDefs.defs)
            register(proj4)

            const projection_ = new proj.Projection({
                code: dataProjection,
                units: coorDefs?.unit || 'm',
                axisOrientation: 'neu',
                //   extent: coorDefs?.extent?.length ? coorDefs.extent.map(Number) : null // options conflict in types?
            })
            if (coorDefs?.extent?.length) {
                projection_.setExtent(coorDefs.extent.map(Number))
            }

            // 如果已经在 OL 中注册（通过 register(proj4)），可能不需要手动 addProjection，但为了保险
            // proj4.defs 注册后，OL 的 proj4 插件会自动识别

            return projection_ // 或者 use proj.get(dataProjection)

        } catch (e) {
            console.error('Proj4 registration failed', e)
        }
    }

    // Fallback to getting by code (allows things like 'EPSG:xxx' if already known by proj4 or OL)
    // 如果 tileProjectionCode 是 'GCJ02' 或 'BD09' 等如果未定义会返回 null
    return proj.get(tileProjectionCode)
}

import * as React from "react"
import { cn } from "@/lib/utils"
// @ts-ignore
import { Tile as TileLayer } from 'ol/layer'
// @ts-ignore
import { XYZ as XYZSource } from 'ol/source'
// @ts-ignore
import * as style from 'ol/style'
import type Map from 'ol/Map'
import { useMap } from '../map-container/map-container'
import _ from 'lodash'
import { getProjection, getMapCoordinateType } from './utils'


export interface CanvasSetting {
  grayscale?: number
  invert?: number
  sepia?: number
  'hue-rotate'?: number
  saturate?: number
  brightness?: number
  contrast?: number
}

export interface CoorDefs {
  defs?: string
  extent?: number[]
  unit?: 'degrees' | 'ft' | 'm' | 'pixels' | 'tile-pixels' | 'us-ft'
  dataProjection?: string
}

export interface LayerBase {
  opacity?: number
  zIndex?: number
  maxResolution?: number
  minResolution?: number
  maxZoom?: number
  minZoom?: number
}

export interface XYZProps {
  source?: string
  coordinateType?: string
  coorDefs?: CoorDefs
  canvasFilter?: boolean
  canvasSetting?: CanvasSetting | CanvasSetting[]
  layerBase?: LayerBase
  display?: boolean
  className?: string
  cellKey?: string
  map?: Map | null
}

const XYZ = React.forwardRef<HTMLDivElement, XYZProps>(
  (props, ref) => {
    const {
      className,
      cellKey,
      source: sourceUrl,
      coordinateType,
      coorDefs,
      canvasFilter,
      canvasSetting,
      layerBase,
      display = true,
      map: mapProp,
      ...otherProps
    } = props

    const contextMap = useMap()
    const map = mapProp || contextMap
    const layerRef = React.useRef<any>(null)
    const refreshKeyRef = React.useRef(0)

    const { opacity, zIndex, maxResolution, minResolution, maxZoom, minZoom } = layerBase || {}

    // Cache Busting
    const appendCacheBust = React.useCallback((url: string | undefined, key: number) => {
      if (!url) return url
      const join = url.indexOf('?') >= 0 ? '&' : '?'
      return `${url}${join}_v=${key}`
    }, [])

    // Tile Load Function
    const tileLoadFunction = React.useCallback((imageTile: any, src: string) => {
      const tileImg = imageTile.getImage() as HTMLImageElement

      // 未启用滤镜时，走默认加载逻辑
      if (!canvasFilter || !canvasSetting) {
        tileImg.src = src
        return
      }

      const img = new Image()
      img.crossOrigin = 'anonymous'

      const fallbackToSrc = (retry = false) => {
        if (retry) {
          const join = src.indexOf('?') >= 0 ? '&' : '?'
          tileImg.src = `${src}${join}_rt=${Date.now()}`
        } else {
          tileImg.src = src
        }
      }

      img.onerror = function () {
        fallbackToSrc(true)
      }

      img.onload = function () {
        try {
          const canvas = document.createElement('canvas')
          const w = img.width
          const h = img.height
          canvas.width = w
          canvas.height = h
          const context = canvas.getContext('2d')

          // Handle array vs object for canvasSetting
          let initValue: CanvasSetting | undefined
          if (Array.isArray(canvasSetting) && !_.isEmpty(canvasSetting)) {
            initValue = canvasSetting[0]
          } else if (_.isPlainObject(canvasSetting) && !_.isEmpty(canvasSetting)) {
            initValue = canvasSetting as CanvasSetting
          }

          if (context && initValue) {
            const { grayscale = 0, invert = 0, sepia = 0, saturate = 100, brightness = 100, contrast = 100 } = initValue
            const hueRotate = initValue['hue-rotate'] || 0

            context.filter = `grayscale(${grayscale}%) invert(${invert}%) sepia(${sepia}%) hue-rotate(${hueRotate}deg) saturate(${saturate}%) brightness(${brightness}%) contrast(${contrast}%)`
          }

          if (context) {
            context.drawImage(img, 0, 0, w, h, 0, 0, w, h)
            try {
              tileImg.src = canvas.toDataURL('image/png')
            } catch (e) {
              fallbackToSrc(true)
            }
          } else {
            fallbackToSrc()
          }
        } catch (e) {
          fallbackToSrc(true)
        }
      }

      img.src = src
    }, [JSON.stringify({ canvasFilter, canvasSetting })])

    // Create Layer
    React.useEffect(() => {
      if (!map) return

      const mapCoordinateType = getMapCoordinateType(map)
      const initUrl = appendCacheBust(sourceUrl, refreshKeyRef.current)

      // Projection Logic
      const projection = getProjection(coorDefs, coordinateType, mapCoordinateType)

      const geoSource = new XYZSource({
        cacheSize: 0,
        url: initUrl,
        crossOrigin: 'anonymous',
        projection: projection,
        tileLoadFunction
      } as any)

      const layer = new TileLayer({
        opacity,
        zIndex,
        maxResolution,
        minResolution,
        maxZoom,
        minZoom,
        source: geoSource,
        // rotation: 76,
        changeSelect: true,
        style: (_feature: any, _type: any) => new style.Style({ image: new style.Icon({ src: '' }) }),
        properties: { layerType: 'xyz', cellKey } // Preserve custom props
      } as any)

      layerRef.current = layer
      map.addLayer(layer)

      return () => {
        if (map && layer) {
          map.removeLayer(layer)
        }
      }
    }, [map, sourceUrl, coordinateType, JSON.stringify(coorDefs), tileLoadFunction]) // Removed props dependencies that are handled by updates

    // Update Layer Source/Refresh
    React.useEffect(() => {
      const layer = layerRef.current
      if (!layer) return
      const src = layer.getSource()
      if (!src) return

      if (!display) return

      refreshKeyRef.current += 1
      if (src.setUrl && sourceUrl) {
        src.setUrl(appendCacheBust(sourceUrl, refreshKeyRef.current))
      }
      if (src.clear) src.clear()
      if (src.refresh) src.refresh()

    }, [appendCacheBust, display, sourceUrl, JSON.stringify({ canvasFilter, canvasSetting }), coordinateType, JSON.stringify(coorDefs)])

    // Update Layer Properties (useLayerProperties logic equivalent)
    React.useEffect(() => {
      const layer = layerRef.current
      if (!layer) return

      if (opacity !== undefined) layer.setOpacity(opacity)
      if (zIndex !== undefined) layer.setZIndex(zIndex)
      if (maxResolution !== undefined) layer.setMaxResolution(maxResolution)
      if (minResolution !== undefined) layer.setMinResolution(minResolution)
      if (maxZoom !== undefined) layer.setMaxZoom(maxZoom)
      if (minZoom !== undefined) layer.setMinZoom(minZoom)

      // Visibility
      if (display !== undefined) layer.setVisible(display)

    }, [opacity, zIndex, maxResolution, minResolution, maxZoom, minZoom, display])


    return (
      <div
        ref={ref}
        className={cn("xyz-layer", className)}
        style={{ display: 'none' }}
        data-cell-key={cellKey}
        {...otherProps}
      />
    )
  }
)

XYZ.displayName = "XYZ"

export { XYZ }

import * as React from "react"
import type { DateRange } from "react-day-picker"

import { cn } from "@/lib/utils"
import { format } from "date-fns"
import { Calendar } from "@/components/ui/calendar"
import {
  Drawer,
  DrawerContent,
  DrawerTrigger,
} from "@/registry/ui/drawer"

export interface MobileCalendarProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, "children" | "onChange"> {
  /**
   * 模式
   */
  mode?: "picker" | "calendar"
  /**
   * 日期选择类型
   */
  selectionMode?: "single" | "range"
  /**
   * 最小日期
   */
  min?: string
  /**
   * 最大日期
   */
  max?: string
  /**
   * 是否允许清除
   */
  allowClear?: boolean
  /**
   * 当前值
   */
  value?: string | string[]
  /**
   * 默认值
   */
  defaultValue?: string | string[]
  /**
   * 值变化回调
   */
  onChange?: (value: string | string[]) => void
  /**
   * 占位符文字
   */
  placeholder?: string
  /**
   * 是否禁用
   */
  disabled?: boolean
}

const MobileCalendar = React.forwardRef<HTMLDivElement, MobileCalendarProps>(
  (
    {
      className,
      mode = "picker",
      selectionMode = "single",
      min,
      max,
      allowClear = true,
      value,
      defaultValue,
      onChange,
      placeholder = "请选择",
      disabled = false,
      ...props
    },
    ref
  ) => {

    const convertToDate = (value?: string | string[]): Date | DateRange | undefined => {
      if (!value) return undefined
      if (Array.isArray(value)) {
        if (value.length === 0) return undefined
        return { from: new Date(value[0]), to: new Date(value[1]) }
      }
      return new Date(value)
    }

    const [visible, setVisible] = React.useState(false)
    const [internalValue, setInternalValue] = React.useState(defaultValue || "")
    const [pickerValue, setPickerValue] = React.useState<Date | DateRange | undefined>(
      convertToDate(defaultValue ?? "")
    )

    // 处理默认值
    React.useEffect(() => {
      if (defaultValue) {
        setInternalValue(defaultValue)
        setPickerValue(convertToDate(defaultValue))
      }
    }, [defaultValue])

    // 处理值变化
    React.useEffect(() => {
      if (value !== undefined) {
        setInternalValue(value)
        setPickerValue(convertToDate(value))
      }
    }, [value])

    const convertToString = (value: Date | DateRange | undefined): string | string[] => {
      if (!value) return ""
      if (selectionMode === "range" && value && "from" in value) {
        if (value.to) {
          return [
            format(value.from!, "yyyy-MM-dd"),
            format(value.to, "yyyy-MM-dd")
          ]
        }
        if (value.from) {
          return format(value.from, "yyyy-MM-dd")
        }
        return ""
      }
      return format(value as Date, "yyyy-MM-dd")
    }

    const handleDateChange = (dates: Date | DateRange | undefined) => {      
      if (!dates && !allowClear) return

      if (mode === "picker") {
        setPickerValue(dates)
      } else {
        const stringValue = convertToString(dates)
        setPickerValue(dates)
        setInternalValue(stringValue)
        onChange?.(stringValue)
      }
    }

    const handleConfirm = () => {
      if (mode === "picker") {
        const stringValue = convertToString(pickerValue)
        setInternalValue(stringValue)
        onChange?.(stringValue)
        setVisible(false)
      }
    }

    const displayValue = Array.isArray(internalValue)
      ? internalValue.join(" - ")
      : internalValue

    const placeholderText = !internalValue ? placeholder : displayValue

    return (
      <div ref={ref} className={cn("mobile-calendar px-3 py-2 border border-slate-300 rounded-lg", className)} {...props}>
        {
          mode === "calendar" ? (
            <Calendar
              mode={selectionMode}
              selected={pickerValue}
              onSelect={handleDateChange}
              disabled={disabled ? disabled : { after: max ? new Date(max) : undefined, before: min ? new Date(min) : undefined }}
              className="w-full overflow-y-auto"
              {...((selectionMode === "range" ? { required: true } : {}) as any)}
            />
          ) : <Drawer
            open={visible}
            onOpenChange={(open) => mode === "picker" ? setVisible(open) : undefined}
          >
            <DrawerTrigger asChild>
              <div className="cursor-pointer">{placeholderText}</div>
            </DrawerTrigger>
            <DrawerContent mask className="max-h-[50vh]">
              <div className="flex justify-between items-center px-4 py-2 border-bx">
                <button
                  type="button"
                  className="text-primary px-3 py-1"
                  onClick={() => setVisible(false)}
                >
                  取消
                </button>
                <div className="flex items-center gap-2">
                  <button
                    type="button"
                    className="text-primary px-3 py-1"
                    onClick={handleConfirm}
                  >
                    确定
                  </button>
                </div>
              </div>
              <Calendar
                mode={selectionMode}
                selected={pickerValue}
                onSelect={handleDateChange}
                disabled={disabled ? disabled : { after: max ? new Date(max) : undefined, before: min ? new Date(min) : undefined }}
                className="w-full overflow-y-auto"
                {...((selectionMode === "range" ? { required: true } : {}) as any)}
              />
            </DrawerContent>
          </Drawer>
        }
      </div>
    )
  }
)
