import * as React from 'react'
import { createAPI } from '@airiot/client'
import { Loader2 } from 'lucide-react'
import { fieldRender } from '@/registry/blocks/table-field/table-field-relate/utils'
import debounce from 'lodash/debounce'

export interface TableFieldReferenceProps {
  schema?: {
    key?: string
    searchRelate?: {
      field?: {
        key?: string
        fieldSchema?: any
      }
    }
    numberFormat?: string
  }
  field?: {
    key?: string
  }
  option?: {
    schema?: {
      name?: string
    }
  }
  tableData?: any
}

const TableFieldReference: React.FC<TableFieldReferenceProps> = (props) => {
  const { schema, field, option, tableData } = props
  const [data, setData] = React.useState<any>({})
  const [val, setVal] = React.useState<any>()
  const [loading, setLoading] = React.useState(false)

  // 使用防抖更新数据
  const debouncedSetData = React.useMemo(
    () => debounce((v: any) => setData(v), 800),
    []
  )

  React.useEffect(() => {
    if (tableData) {
      debouncedSetData(tableData)
    }
  }, [tableData, debouncedSetData])

  React.useEffect(() => {
    // 从 schema.name 或 option.schema.name 中提取 tableId
    // 格式: core/t/表ID/d
    const schemaName = option?.schema?.name || ''
    const tableId = schemaName?.split('/')?.[2]

    if (tableId) {
      setLoading(true)
      const api = createAPI({
        resource: 'computerecord/computerecord/search',
        name: 'reference'
      })

      // 使用 fetch 调用计算记录 API
      api
        .query({}, {
          method: 'POST',
          body: JSON.stringify({
            tableId,
            data: data || {}
          })
        } as any)
        .then((result: any) => {
          if (result && !isEmpty(result)) {
            setVal(result)
          }
        })
        .catch((err) => {
          console.error('查找引用计算失败:', err)
        })
        .finally(() => {
          setLoading(false)
        })
    }
  }, [data, option?.schema?.name])

  if (loading) {
    return (
      <div className="flex items-center gap-2 text-sm text-muted-foreground">
        <Loader2 className="h-4 w-4 animate-spin" />
        计算中...
      </div>
    )
  }

  const displayValue = val?.[field?.key || schema?.key]
  const fieldSchema = schema?.searchRelate?.field?.fieldSchema

  return (
    <span>
      {fieldRender(displayValue, fieldSchema)}
    </span>
  )
}

function isEmpty(obj: any) {
  return obj === null || obj === undefined || Object.keys(obj).length === 0
}

export { TableFieldReference }
export default TableFieldReference

import * as React from 'react'
import isArray from 'lodash/isArray'
import isObject from 'lodash/isObject'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import { Button } from '@/components/ui/button'
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@/components/ui/tooltip'
import { Crosshair, Loader2 } from 'lucide-react'
import { createAPI } from '@airiot/client'
import { dealFilter, getQueryFilter } from './utils'
import type { RelateFieldOption } from './types'

interface AsyncSelectProps {
  input?: {
    value?: any
    onChange?: (value: any) => void
  }
  field?: {
    schema?: Record<string, any>
    filter?: any
    meta?: any
    key?: string
    displayField?: string
    tableID?: string
    relateShowFields?: Array<{
      key: string
      title: string
      mapToCurrent?: boolean
      mapField?: string
      fieldSchema?: any
    }>
    option?: {
      form?: {
        change: (field: string, value: any) => void
      }
    }
  }
  meta?: any
  record?: any
  antdForm?: any
  label?: string
  disabled?: boolean
  value?: {
    key: string
    label: string
    item?: any
  } | null | {
    key: string
    label: string
    item?: any
  }[]
  mode?: 'multiple' | 'tags'
  isOptionSelected?: (option: RelateFieldOption) => boolean
  style?: React.CSSProperties
  onChange?: (value: any) => void
}

/**
 * AsyncSelect - 异步选择器组件
 * 支持搜索、分页加载、精确搜索
 */
const AsyncSelect: React.FC<AsyncSelectProps> = (props) => {
  const {
    field = {},
    label = '请选择',
    disabled = false,
    mode,
    value: propValue,
    onChange,
    style,
  } = props

  const { displayField = 'name', schema, relateShowFields } = field

  // 状态管理
  const [loading, setLoading] = React.useState(false)
  const [pageLoading, setPageLoading] = React.useState(false)
  const [options, setOptions] = React.useState<RelateFieldOption[]>([])
  const [allOptions, setAllOptions] = React.useState<RelateFieldOption[]>([])
  const [page, setPage] = React.useState(0)
  const [count, setCount] = React.useState(50)
  const [precise, setPrecise] = React.useState(false)
  const [searchValue, setSearchValue] = React.useState('')

  const itemsRef = React.useRef<RelateFieldOption[]>([])
  const currentPageRef = React.useRef(0)

  // 获取选项数据
  const loadOptions = React.useCallback(
    async (inputValue: string = '', pageNum: number = 0): Promise<number> => {
      if (currentPageRef.current >= pageNum && pageNum !== 0) {
        return 0
      }
      if (pageNum === 0) {
        itemsRef.current = []
        currentPageRef.current = 0
      }
      currentPageRef.current = pageNum

      let filterObj: any = {}
      if (inputValue) {
        filterObj = precise
          ? { [displayField]: inputValue }
          : { [displayField]: { $like: inputValue } }
      }

      dealFilter(filterObj, field, getQueryFilter)

      setLoading(true)
      try {
        const tableName = (schema || field.schema)?.name
        if (!tableName) {
          console.warn('缺少 schema.name')
          return 0
        }

        // 创建 API 实例
        const api = createAPI({
          resource: tableName,
          name: 'relate'
        })

        // 使用 api.query 查询数据
        const { items } = await api.query(
          {
            limit: 50,
            skip: pageNum * 50,
            fields: ['id', displayField].filter(Boolean),
            ...(inputValue && { search: filterObj })
          }
        )

        const newOptions = items.map((item: any) => ({
          value: item.id,
          label: item[displayField] || item.name || item.id,
          key: item.id,
          item,
        }))

        itemsRef.current = [...itemsRef.current, ...newOptions]
        setOptions(itemsRef.current)
        setCount(items.length || 0)

        return items.length || 0
      } catch (error) {
        console.error('加载选项失败:', error)
        setOptions([])
        return 0
      } finally {
        setLoading(false)
      }
    },
    [JSON.stringify(field), displayField, schema, relateShowFields, precise]
  )

  // 初始加载
  React.useEffect(() => {
    loadOptions()
  }, [loadOptions])

  // 合并去重选项
  React.useEffect(() => {
    setAllOptions((before) => {
      return before
        .concat(options)
        .filter(
          (option, index, self) =>
            index === self.findIndex((t) => t.value === option.value)
        )
    })
  }, [options])

  // 多字段联动表单其他字段
  React.useEffect(() => {
    relateShowFields?.forEach((rsf) => {
      if (rsf.mapToCurrent && rsf.mapField) {
        const itemValue = isArray(propValue) ? propValue[0]?.item?.[rsf.key] : (propValue as any)?.item?.[rsf.key]
        if (itemValue) {
          field?.option?.form?.change(rsf.mapField, itemValue)
        }
      }
    })
  }, [JSON.stringify(propValue || {}), relateShowFields, field])

  // 处理值变化
  const handleChange = (selectedValue: string | string[]) => {
    if (!selectedValue || (isArray(selectedValue) && selectedValue.length === 0)) {
      onChange?.(mode === 'multiple' ? [] : {})
      return
    }

    if (mode === 'multiple' && isArray(selectedValue)) {
      const selectedOptions = selectedValue
        .map((key) => {
          const result = allOptions.find((item) => item.value === key)
          return result || (isArray(propValue) && propValue.find((v: any) => v?.key === key)) || null
        })
        .filter(Boolean)

      onChange?.(selectedOptions)
    } else {
      const selectedOption = allOptions.find((opt) => opt.value === selectedValue)
      onChange?.(selectedOption || {})
    }
  }

  // 处理搜索
  const handleSearch = async (value: string) => {
    setSearchValue(value)
    const _count = await loadOptions(value, 0)
    setCount(_count)
    setPage(0)
  }

  // 切换精确/模糊搜索
  const togglePrecise = () => {
    const _precise = !precise
    setPrecise(_precise)
    handleSearch(searchValue)
  }

  // 加载更多
  const loadMore = React.useCallback(async () => {
    if (pageLoading || count < 50) return

    const nextPage = page + 1
    setPage(nextPage)
    setPageLoading(true)

    const _count = await loadOptions(searchValue, nextPage)
    setCount(_count)
    setPageLoading(false)
  }, [page, pageLoading, count, searchValue, loadOptions])

  // 格式化显示值
  const formatDisplayValue = (val: any): string => {
    if (!val) return ''
    if (typeof val === 'string') return val
    if (isObject(val) && (val as any).label) return (val as any).label
    return String(val)
  }

  const currentValue: any =
    mode === 'multiple'
      ? (isArray(propValue) ? propValue.map((v) => (v as any)?.key || v).filter(Boolean) : [])
      : (propValue as any)?.key || propValue || ''

  return (
    <div style={{ position: 'relative', width: '100%', minWidth: 150, ...style }}>
      <Select
        value={currentValue}
        onValueChange={handleChange}
        disabled={disabled}
      >
        <SelectTrigger>
          <SelectValue placeholder={label}>
            {mode === 'multiple' && isArray(propValue) && propValue.length > 0
              ? propValue.map((v) => formatDisplayValue(v)).join(', ')
              : formatDisplayValue(currentValue)}
          </SelectValue>
        </SelectTrigger>
        <SelectContent>
          {loading && options.length === 0 ? (
            <div className="flex items-center justify-center p-4">
              <Loader2 className="h-4 w-4 animate-spin" />
              <span className="ml-2">加载中...</span>
            </div>
          ) : options.length === 0 ? (
            <div className="p-4 text-center text-sm text-muted-foreground">暂无数据</div>
          ) : (
            <>
              {options.map((option) => (
                <SelectItem key={option.value} value={option.value}>
                  {option.label}
                </SelectItem>
              ))}
              {loading && page > 0 && (
                <div className="flex items-center justify-center p-2 text-sm text-muted-foreground">
                  <Loader2 className="h-3 w-3 animate-spin mr-1" />
                  加载中...
                </div>
              )}
              {!loading && count < 50 && page > 0 && (
                <div className="text-center p-2 text-sm text-muted-foreground">
                  已加载全部
                </div>
              )}
              {count === 50 && !loading && (
                <div className="text-center p-2">
                  <Button variant="ghost" size="sm" onClick={loadMore} disabled={pageLoading}>
                    {pageLoading ? (
                      <>
                        <Loader2 className="h-3 w-3 animate-spin mr-1" />
                        加载中...
                      </>
                    ) : (
                      '加载更多'
                    )}
                  </Button>
                </div>
              )}
            </>
          )}
        </SelectContent>
      </Select>

      <TooltipProvider>
        <Tooltip>
          <TooltipTrigger asChild>
            <Button
              variant="ghost"
              size="icon"
              className="absolute right-8 top-1/2 -translate-y-1/2 h-6 w-6"
              onClick={togglePrecise}
            >
              <Crosshair className={`h-3 w-3 ${precise ? 'text-green-600' : ''}`} />
            </Button>
          </TooltipTrigger>
          <TooltipContent>
            <p>{precise ? '模糊搜索' : '精确搜索'}</p>
          </TooltipContent>
        </Tooltip>
      </TooltipProvider>
    </div>
  )
}

export default AsyncSelect

import * as React from 'react'
import isEmpty from 'lodash/isEmpty'
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover'
import { Button } from '@/components/ui/button'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from '@/components/ui/dialog'
import { Loader2 } from 'lucide-react'
import { useUser } from '@airiot/client'
import { createAPI } from '@airiot/client'
import { fieldRender } from './utils'

interface DetailShowProps {
  children?: React.ReactNode
  schema?: any
  value?: any
  fieldRender?: (app: any) => (component: any, schema: any) => (props: any) => React.ReactNode
  inList?: boolean
}

/**
 * DetailShow - 详情展示组件
 * 支持在列表中展示关联数据的详情
 * 可以通过 popover、modal、或跳转页面展示
 */
const DetailShow: React.FC<DetailShowProps> = ({
  children,
  schema,
  value,
  fieldRender: customFieldRender,
  inList = false,
}) => {
  const [visible, setVisible] = React.useState(false)
  const [detailData, setDetailData] = React.useState<Array<{ title: string; value: any }>>([])
  const [loading, setLoading] = React.useState(false)

  const { user } = useUser()

  // 获取详情数据
  const getDetailData = async () => {
    if (!value?.id || !schema?.relate?.id) {
      return
    }

    setLoading(true)

    try {
      // 创建 schema API 实例
      const schemaAPI = createAPI({
        resource: 'core/t/schema',
        name: 'schema'
      })

      // 获取关联表的结构
      const relateTable = await schemaAPI.get(schema.relate.id)

      if (!relateTable || !relateTable.schema) {
        console.error('该表已被删除')
        setLoading(false)
        return
      }

      // 创建数据 API 实例
      const dataAPI = createAPI({
        resource: `core/t/${schema.relate.id}/d`,
        name: 'data'
      })

      // 获取记录详情
      const data = await dataAPI.get(value.id)

      setLoading(false)

      if (isEmpty(data)) {
        console.error('该条数据已被删除')
        return
      }

      // 构建详情数据
      const result: Array<{ title: string; value: any }> = []

      if (schema.recordDetail?.showField) {
        schema.recordDetail.showField.forEach((key: string) => {
          const fieldSchema = relateTable.schema.properties[key]
          let fieldValue = data?.[key]

          // 使用自定义 fieldRender 或默认 fieldRender
          if (customFieldRender && customFieldRender(null)(null, fieldSchema)) {
            fieldValue = customFieldRender(null)(null, fieldSchema)({
              value: fieldValue,
              wrap: 'span',
            })
          } else {
            fieldValue = fieldRender(fieldValue, fieldSchema)
          }

          const title = fieldSchema?.title || key
          result.push({ title, value: fieldValue })
        })
      } else if (schema.relateShowFields?.length > 0) {
        // 使用 relateShowFields
        schema.relateShowFields.forEach((field: any) => {
          const fieldValue = data?.[field.key]
          result.push({
            title: field.title,
            value: fieldRender(fieldValue, field.fieldSchema),
          })
        })
      }

      setDetailData(result)
    } catch (error) {
      console.error('获取数据失败:', error)
      setLoading(false)
    }
  }

  if (!value?.id) {
    return <>{children || ''}</>
  }

  // Popover 模式
  if (schema.recordDetail?.showType === 'popover') {
    const content = loading ? (
      <div className="flex items-center justify-center p-4">
        <Loader2 className="h-4 w-4 animate-spin" />
      </div>
    ) : (
      <div className="max-h-[500px] overflow-y-auto">
        {detailData.map((item, index) => (
          <div key={index} className="flex py-2 min-h-[35px]">
            <span className="w-24 text-muted-foreground flex-shrink-0">{item.title}：</span>
            <span className="flex-1">{item.value}</span>
          </div>
        ))}
      </div>
    )

    return (
      <Popover>
        <PopoverTrigger asChild>
          <span className="detail-span cursor-pointer underline" onClick={getDetailData}>
            {children}
          </span>
        </PopoverTrigger>
        <PopoverContent className="w-[500px]" align="start">
          {content}
        </PopoverContent>
      </Popover>
    )
  }

  // Modal 模式
  if (schema.recordDetail?.showType === 'modal') {
    return (
      <>
        <span
          className="detail-span cursor-pointer underline"
          onClick={() => {
            getDetailData()
            setVisible(true)
          }}
        >
          {children}
        </span>

        {visible && (
          <Dialog open={visible} onOpenChange={setVisible}>
            <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto">
              <DialogHeader>
                <DialogTitle>记录详情</DialogTitle>
              </DialogHeader>

              {loading ? (
                <div className="flex items-center justify-center py-8">
                  <Loader2 className="h-6 w-6 animate-spin" />
                </div>
              ) : (
                <div className="space-y-2">
                  {detailData.map((item, index) => (
                    <div key={index} className="flex py-2 min-h-[35px]">
                      <span className="w-48 text-muted-foreground flex-shrink-0">{item.title}：</span>
                      <span className="flex-1">{item.value}</span>
                    </div>
                  ))}
                </div>
              )}

              <DialogFooter>
                <Button variant="outline" onClick={() => setVisible(false)} type="button">
                  关闭
                </Button>
              </DialogFooter>
            </DialogContent>
          </Dialog>
        )}
      </>
    )
  }

  // Page 模式 - TODO: 需要实现路由跳转
  if (schema.recordDetail?.showType === 'page') {
    return (
      <span
        className="detail-span cursor-pointer underline"
        onClick={() => {
          // TODO: 实现页面跳转
          // app.go(`/app/table/${schema?.relate?.id}/${value?.id}/detail`)
          console.log('跳转到详情页:', `/app/table/${schema?.relate?.id}/${value?.id}/detail`)
        }}
      >
        {children}
      </span>
    )
  }

  // Card 模式
  if (schema.relateShowFields?.length > 0 && schema.showType === 'card') {
    const content = (
      <div className="inline-block bg-muted p-3 rounded-md m-1 min-w-[300px]">
        <div className="flex py-1">
          <span className="w-24 text-muted-foreground flex-shrink-0">记录编号：</span>
          <span>{value.id}</span>
        </div>
        {schema.relateShowFields.map((f: any) => (
          <div key={f.key} className="flex py-1">
            <span className="w-24 text-muted-foreground flex-shrink-0">{f.title}：</span>
            <span>{fieldRender(value[f.key], f.fieldSchema)}</span>
          </div>
        ))}
      </div>
    )

    if (inList) {
      return (
        <Popover>
          <PopoverTrigger asChild>
            <span className="cursor-pointer">{children || ''}</span>
          </PopoverTrigger>
          <PopoverContent>{content}</PopoverContent>
        </Popover>
      )
    } else {
      return <>{content}</>
    }
  }

  return <>{children || ''}</>
}

export default DetailShow

import * as React from 'react'
import isEmpty from 'lodash/isEmpty'
import isArray from 'lodash/isArray'
import isObject from 'lodash/isObject'
import AsyncSelect from './AsyncSelect'

export interface TableFieldRelateProps {
  input?: {
    value?: any
    onChange?: (value: any) => void
  }
  field?: {
    schema?: Record<string, any> | undefined
    filter?: any
    meta?: any
    key?: string | undefined
    displayField?: string | undefined
    tableID?: string | undefined
    relateShowFields?: any
    option?: any
    internalTable?: boolean
  }
  meta?: any
  record?: any
  disabled?: boolean
}

/**
 * TableFieldRelate - 简单关联字段组件
 * 用于内部表关联（同一个表内的字段关联）
 */
const TableFieldRelate: React.FC<TableFieldRelateProps> = (props) => {
  const { input, field = {}, meta, record, disabled: propsDisabled } = props
  const { onChange, value } = input || {}
  const { displayField = 'name', schema, internalTable = true } = field

  const disabled = propsDisabled || meta?.data?.disabled || false

  // 格式化显示值
  const formatDisplayValue = (val: any): string => {
    if (!val) return ''
    if (isObject(val) && !isArray(val)) {
      return (val as any)[displayField] || (val as any).name || ''
    }
    if (isArray(val)) {
      return val.map((v) => (isObject(v) ? (v as any)[displayField] || (v as any).name : v)).join(', ')
    }
    return String(val)
  }

  // 处理值变化
  const handleChange = (val: any) => {
    if (!val || isEmpty(val)) {
      onChange?.(null)
    } else if (internalTable) {
      onChange?.(val)
    } else {
      onChange?.({ in: val })
    }
  }

  // 格式化当前值
  const currentValue = React.useMemo(() => {
    if (!value) return undefined
    if ((value as any).ne) return undefined
    if (disabled) {
      if (isArray(value)) {
        return value.map((v: any) => (v as any)[displayField])
      }
      return (value as any)[displayField]
    }
    if ((value as any).in || (value as any).nin) {
      return (value as any).in || (value as any).nin
    }
    return value
  }, [value, disabled, displayField])

  return (
    <AsyncSelect
      value={
        currentValue
          ? isArray(currentValue)
            ? currentValue.map((v: any) => ({
                key: isObject(v) ? (v as any).id || (v as any).value : v,
                label: isObject(v) ? (v as any).label || (v as any).name : v,
                item: v,
              }))
            : {
                key: isObject(currentValue) ? (currentValue as any).id || (currentValue as any).value : currentValue,
                label: formatDisplayValue(currentValue),
                item: currentValue,
              }
          : null
      }
      onChange={(option) => {
        if (!option || (isArray(option) && option.length === 0)) {
          onChange?.(null)
        } else if (isArray(option)) {
          handleChange(option.map((o: any) => o.value || o.key))
        } else {
          handleChange((option as any).value || (option as any).key)
        }
      }}
      field={field}
      label={`请选择${(schema as any)?.title || '关联字段'}`}
      disabled={disabled}
      mode={internalTable ? undefined : 'multiple'}
      meta={meta}
      record={record}
    />
  )
}

