    } else {
      onChange?.(option.item)
    }
  }

  return (
    <AsyncSelect
      value={
        item
          ? {
              key: item.id,
              label: item[displayField],
              item,
            }
          : null
      }
      onChange={handleChange}
      field={field}
      label={label}
      disabled={disabled}
      meta={meta}
      record={record}
    />
  )
}

