const TableShow: React.FC<TableFieldRelatePlusDataShowProps> = (props) => {
  const { relateSchema, field, val } = props
  const tableID = relateSchema?.relate?.id

  const [loading, setLoading] = React.useState(true)
  const [tableSchema, setTableSchema] = React.useState<any>(null)

  React.useEffect(() => {
    if (tableID) {
      const schemaAPI = createAPI({
        resource: 'core/t/schema',
        name: 'schema'
      })

      schemaAPI.get(tableID)
        .then(({ schema }: any) => {
          setTableSchema(schema)
          setLoading(false)
        })
        .catch(() => {
          setLoading(false)
        })
    } else {
      setLoading(false)
    }
  }, [tableID])

  if (loading) {
    return (
      <div className="flex items-center justify-center py-4">
        <div className="text-sm text-muted-foreground">加载中...</div>
      </div>
