export interface TableFieldUploadProps {
  input: {
    value?: any
    onChange?: (value: any) => void
  }
  field?: {
    schema?: {
      styleType?: 'picture-card' | 'text' | 'video' | 'audio'
      accept?: string
      size?: number
      width?: number
      height?: number
      maxUploadNum?: number
      disabled?: boolean
      onlyCamera?: boolean
      uploadPosition?: 'media' | 'local'
      uploadFolder?: boolean
      folderType?: 'folder' | 'upload'
      folder?: string
      base64?: boolean
      autoZip?: boolean
      autoName?: boolean
      watermark?: any
      sort?: 'asc' | 'desc'
      mediaDelete?: boolean
      ftp?: boolean
      textToAudio?: boolean
      defaultVal?: any
      defaultValType?: string
      key?: string
      [key: string]: any
    }
    filter?: any
    meta?: any
  }
  cellKey?: string
  type?: 'upload_attachment' | 'upload_attachment_group'
  meta?: any
  record?: any
}

const TableFieldUpload = React.forwardRef<HTMLDivElement, TableFieldUploadProps>(
  (props, ref) => {
    const { input, field, cellKey, type } = props
    const { value, onChange } = input || {}
    const schema = field?.schema || {}

    const { user } = useUser()
    const api = createAPI({ name: 'media' })

    const isSingleUpload = type === 'upload_attachment'
    const styleType = schema.styleType || 'picture-card'
    const accept = getAccept(schema.accept, styleType)

    // 上传地址
    console.log('api', api, user)
    const uploadUrl = api.host + '/core/mediaLibrary/upload?action=' +
      (schema.onlyCamera ? 'rename' : 'cover')
    const catalog = schema.folderType === 'folder' ? ('&catalog=' + schema.folder) : ''
    const fullUploadUrl = uploadUrl + catalog

    // 获取请求头
    const getHeaders = () => {
      const headers = (api as any).headers || {}
      // 移除 Content-Type 让浏览器自动设置（FormData 需要）
      const { 'Content-Type': _, ...rest } = headers as any
      return rest
    }

    const [fileList, setFileList] = React.useState<any[]>(() => {
      if (isSingleUpload) {
        return value && value !== '' ? [value] : []
      } else {
        return isArray(value) ? value : []
      }
    })

    const [preview, setPreview] = React.useState({
      visible: false,
      image: '',
      title: ''
    })

    // 默认值生效
    React.useEffect(() => {
      setTimeout(() => {
        if (!value && schema?.defaultVal && onChange && schema?.defaultValType !== 'logic') {
          onChange(schema.defaultVal)
        }
      })
    }, [])

    React.useEffect(() => {
      if (value === 'loading') return
      setFileList(() => {
        if (isSingleUpload) {
          return value && value !== '' ? [value] : []
        } else {
          return isArray(value) ? value : []
        }
      })
    }, [isSingleUpload, value])

    const cKey = schema.key || cellKey
    const width = schema.width
    const height = schema.height

    const showPreview = async (file: any) => {
      const fileType = file.name.substring(file.name.lastIndexOf('.') + 1)
      if (['png', 'jpg', 'jpeg', 'gif'].indexOf(fileType) === -1) return
      if (file.response?.url) {
        file.preview = getMediaUrl(file.response.url)
      } else if (!file.url && !file.preview) {
        file.preview = file.originFileObj instanceof Blob
          ? await getBase64(file.originFileObj)
          : file.thumbUrl
      }
      setPreview({
        visible: true,
        image: file.preview || file.url,
        title: file.name || file.url.substring(file.url.lastIndexOf('/') + 1)
      })
    }

    const onRemoveChange = (file: any) => {
      if (isSingleUpload) {
        onChange?.(null)
        setFileList([])
      } else {
        const filtered = fileList.filter((f: any) => f.uid !== file.uid)
        if (filtered.length === 0) {
          setFileList([])
          onChange?.(null)
        } else {
          onChange?.(filtered)
          setFileList(filtered)
        }
      }
    }

    const onRemove = (file: any) => {
      return new Promise((resolve) => {
        if (schema.mediaDelete) {
          // TODO: 显示删除确认对话框
          onRemoveChange(file)
          resolve(false)
        } else {
          onRemoveChange(file)
          resolve(false)
        }
      })
    }

    // 处理文件上传
    const handleFileUpload = async (file: File) => {
      // 检查上传数量限制
      if (isNumber(schema.maxUploadNum) && fileList.length >= schema.maxUploadNum!) {
        console.warn(`最多上传${schema.maxUploadNum}个文件`)
        return
      }

      const uid = Date.now() + Math.random().toString(36).substring(2, 9)

      // 创建文件对象
      const newFile = {
        uid,
        name: file.name,
        size: file.size,
        status: 'uploading',
        percent: 0,
        originFileObj: file
      }

      // 添加到列表
      setFileList(prev => [...prev, newFile])

      try {
        // 上传前验证
        if (schema.size && file.size / 1024 / 1024 > schema.size) {
          throw new Error(`文件大小不可超过${schema.size}MB`)
        }

        const fileType = file.name.substring(file.name.lastIndexOf('.') + 1)
        if (restrictedFileExtensions.indexOf(fileType) > -1) {
          throw new Error(`不可上传${fileType}文件`)
        }
        if (accept?.indexOf(fileType) === -1) {
          throw new Error('请上传正确类型文件')
        }

        // 自动压缩
        let processedFile = file
        if (schema.autoZip) {
          processedFile = await autoZip(file, schema.autoZip)
        }

        // 自动重命名
        if (schema.autoName) {
          const ext = file.name.split('.')?.[1]
          const newName = Math.random().toString(36).substring(2, 18) + '.' + ext
          processedFile = new File([processedFile], newName, { type: processedFile.type })
        }

        // 加水印
        processedFile = await addWatermark(processedFile, schema.watermark, user)

        // 执行上传
        const response = await uploadFile(
          processedFile,
          fullUploadUrl,
          getHeaders(),
          (percent) => {
            setFileList(prev =>
              prev.map(f =>
                f.uid === uid ? { ...f, percent } : f
              )
            )
          }
        )

        // 上传成功
        const successFile = {
          uid,
          name: processedFile.name,
          size: processedFile.size,
          status: 'done',
          percent: 100,
          url: response.url || response,
          response: response,
          originFileObj: file
        }

        setFileList(prev => {
          const updated = prev.map(f => f.uid === uid ? successFile : f)

          // 触发 onChange
          if (isSingleUpload) {
            onChange?.(successFile)
            return [successFile]
          } else {
            onChange?.(updated)
            return updated
          }
        })

      } catch (error: any) {
        console.error('Upload error:', error)
        const errorFile = {
          uid,
          name: file.name,
          size: file.size,
          status: 'error',
          percent: 0,
          response: { message: error.message || '上传失败' },
          originFileObj: file
        }

        setFileList(prev =>
          prev.map(f => f.uid === uid ? errorFile : f)
        )

        // 从列表中移除失败的文件
        setTimeout(() => {
          setFileList(prev => prev.filter(f => f.uid !== uid))
        }, 2000)
      }
    }

    const hideAddBtn = isSingleUpload && fileList.length >= 1

    const defaultWidth = width || 104
    const defaultHeight = height || 104

    return (
      <div ref={ref} className={cn(
        "custom-upload",
        styleType === 'picture-card' ? 'upload-picture-card' : 'upload-text'
      )}>
        <style>{`
          .upload-list-custom-${cKey} .upload-item-container {
            float: left;
            width: ${defaultWidth}px;
            height: ${defaultHeight}px;
            margin-right: 8px;
          }
        `}</style>

        {/* 图片卡片样式 */}
        {styleType === 'picture-card' ? (
          <div className="table-upload-attach">
            <div className="flex flex-wrap gap-2">
              {fileList.map((file) => (
                <ImageCardItemRender
                  key={file.uid}
                  file={file}
                  onPreview={() => showPreview(file)}
                  onRemove={() => onRemove(file)}
                />
              ))}

              {!hideAddBtn && !schema.disabled && (
                <div
                  className="upload-item-container upload-item-add-btn cursor-pointer hover:bg-slate-100"
                  style={{ width: defaultWidth, height: defaultHeight }}
                >
                  <label className="cursor-pointer w-full h-full flex items-center justify-center">
                    <input
                      type="file"
                      className="hidden"
                      accept={accept}
                      multiple={!isSingleUpload}
                      onChange={(e) => {
                        const files = Array.from(e.target.files || [])
                        files.forEach(file => {
                          handleFileUpload(file)
                        })
                        e.target.value = ''
                      }}
                    />
                    <UploadButton styleType={styleType} />
                  </label>
                </div>
              )}

              {/* 媒体库上传 - TODO */}
              {!schema.disabled && (
                <div className="text-sm text-slate-400 flex items-center justify-center border-2 border-dashed rounded"
                     style={{ width: defaultWidth, height: defaultHeight }}>
                  <div className="text-center p-2">
                    <ImageIcon className="h-8 w-8 mx-auto mb-1 text-slate-400" />
                    <div className="text-xs">等待 MediaModal 迁移</div>
                  </div>
                </div>
              )}
            </div>
          </div>
        ) : (
          /* 文本样式 */
          <div className="space-y-2">
            {fileList.map((file) => (
              <ItemRender
                key={file.uid}
                file={file}
                onRemove={() => onRemove(file)}
              />
            ))}

            {!hideAddBtn && !schema.disabled && (
              <div className="flex gap-2">
                <Button variant="outline" size="sm" asChild>
                  <label className="cursor-pointer">
                    <Upload className="h-4 w-4 mr-2" />
                    上传文件
                    <input
                      type="file"
                      className="hidden"
                      accept={accept}
                      multiple={!isSingleUpload}
                      onChange={(e) => {
                        const files = Array.from(e.target.files || [])
                        files.forEach(file => {
                          handleFileUpload(file)
                        })
                        e.target.value = ''
                      }}
                    />
                  </label>
                </Button>
              </div>
            )}

            {/* 文字转音频 - TODO */}
            {styleType === 'audio' && schema.textToAudio && !(isSingleUpload && fileList.length >= 1) && (
              <div className="text-sm text-slate-400">
                等待 Dashboard.BoradcastButton 迁移
              </div>
            )}

            {/* 媒体库上传 - TODO */}
            {!schema.disabled && (
              <div className="text-sm text-slate-400">
                等待 MediaModal 迁移
              </div>
            )}
          </div>
        )}

        {/* 图片预览对话框 */}
        <Dialog open={preview.visible} onOpenChange={(open) => !open && setPreview({ visible: false, image: '', title: '' })}>
          <DialogContent className="max-w-3xl">
            <DialogHeader>
              <DialogTitle>{preview.title}</DialogTitle>
