// ==================== Actions Container Component ====================

export type ActionType = 'create' | 'edit' | 'delete' | 'view' | 'export' | 'copy'

interface ActionsProps {
  itemId?: string
  item?: any & { id: string }
  modelId?: string
  actions: ActionType[]
  variant?: 'buttons' | 'dropdown'
}

const Actions: React.FC<ActionsProps> = ({
  itemId,
  item,
  actions = ['view', 'edit'],
  variant = 'dropdown'
}) => {
  const id = itemId || item?.id
  if(!id) return null
  // Render as button group
  if (variant === 'buttons') {
    return (
      <div className="flex items-center gap-2">
        {actions.map((action) => (
          action === 'create' ? (
            <CreateAction key={action} />
          ) : action === 'delete' ? (
            <DeleteAction key={action} itemId={id!} />
          ) : action === 'view' ? (
            <ViewAction key={action} itemId={id!} />
          ) : action === 'edit' ? (
            <EditAction key={action} itemId={id!} />
          ) : action === 'export' ? (
            <ExportAction key={action} itemId={id!} />
          ) : action === 'copy' ? (
            <CopyAction key={action} itemId={id!} />
          ) : null
        ))}
      </div>
    )
  }

  // Render as dropdown menu
  const actionLabels: Record<ActionType, string> = {
    create: '新建',
    view: '查看',
    edit: '编辑',
    delete: '删除',
    export: '导出',
    copy: '复制'
  }

  const actionIcons: Record<ActionType, React.ReactNode> = {
    create: <Plus className="h-4 w-4" />,
    view: <Eye className="h-4 w-4" />,
    edit: <Edit className="h-4 w-4" />,
    delete: <Trash2 className="h-4 w-4 text-destructive" />,
    export: <Download className="h-4 w-4" />,
    copy: <Copy className="h-4 w-4" />
  }

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="ghost" size="icon" className="h-8 w-8 p-0">
          <span className="sr-only">打开菜单</span>
          <MoreHorizontal className="h-4 w-4" />
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end">
        {actions.map((action, index) => (
          <React.Fragment key={action}>
            {action === 'create' ? (
              <CreateAction>
                <DropdownMenuItem onSelect={(e) => e.preventDefault()}>
                  {actionIcons[action]}
                  {actionLabels[action]}
                </DropdownMenuItem>
              </CreateAction>
            ) : action === 'delete' ? (
              <DeleteAction itemId={id!}>
                <DropdownMenuItem
                  onSelect={(e) => {
                    e.preventDefault()
                  }}
                >
                  {actionIcons[action]}
                  {actionLabels[action]}
                </DropdownMenuItem>
              </DeleteAction>
            ) : action === 'view' ? (
              <ViewAction itemId={id!}>
                <DropdownMenuItem onSelect={(e) => e.preventDefault()}>
                  {actionIcons[action]}
                  {actionLabels[action]}
                </DropdownMenuItem>
              </ViewAction>
            ) : action === 'edit' ? (
              <EditAction itemId={id!}>
                <DropdownMenuItem onSelect={(e) => e.preventDefault()}>
                  {actionIcons[action]}
                  {actionLabels[action]}
                </DropdownMenuItem>
              </EditAction>
            ) : action === 'export' ? (
              <ExportAction itemId={id!}>
                <DropdownMenuItem onSelect={(e) => e.preventDefault()}>
                  {actionIcons[action]}
                  {actionLabels[action]}
                </DropdownMenuItem>
              </ExportAction>
            ) : action === 'copy' ? (
              <CopyAction itemId={id!}>
                <DropdownMenuItem onSelect={(e) => e.preventDefault()}>
                  {actionIcons[action]}
                  {actionLabels[action]}
                </DropdownMenuItem>
              </CopyAction>
            ) : null}
            {index < actions.length - 1 && <DropdownMenuSeparator />}
          </React.Fragment>
        ))}
      </DropdownMenuContent>
    </DropdownMenu>
  )
}

export default Actions

import React, { useState } from 'react'
import { useModelQuery, useModelFields } from '@airiot/client'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from '@/components/ui/collapsible'
import { Badge } from '@/components/ui/badge'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { ChevronDown, ChevronUp, Plus, Trash2, Filter } from 'lucide-react'

export type FilterFieldType = 'text' | 'number' | 'select' | 'date' | 'date-range'

export interface FilterField {
  name: string
  label: string
  type: FilterFieldType
  options?: { value: string; label: string }[]
  placeholder?: string
}

export interface FilterRule {
  id: string
  field: string
  operator: string
  value: any
  operator2?: string
  value2?: any
}

export type LogicOperator = 'AND' | 'OR'

interface ViewAdvancedFilterProps {
  modelId?: string
  fields?: FilterField[]
  maxRules?: number
  collapsible?: boolean
  defaultCollapsed?: boolean
  showFieldSelector?: boolean
  className?: string
  onFilterChange?: (rules: FilterRule[], logicOperator: LogicOperator) => void
}

const operatorOptions: Record<FilterFieldType, { value: string; label: string }[]> = {
  text: [
    { value: 'contains', label: '包含' },
    { value: 'notContains', label: '不包含' },
    { value: 'eq', label: '等于' },
    { value: 'ne', label: '不等于' },
    { value: 'startsWith', label: '开始于' },
    { value: 'endsWith', label: '结束于' },
    { value: 'empty', label: '为空' },
    { value: 'notEmpty', label: '不为空' },
  ],
  number: [
    { value: 'eq', label: '等于' },
    { value: 'ne', label: '不等于' },
    { value: 'gt', label: '大于' },
    { value: 'gte', label: '大于等于' },
    { value: 'lt', label: '小于' },
    { value: 'lte', label: '小于等于' },
    { value: 'between', label: '介于' },
  ],
  select: [
    { value: 'eq', label: '等于' },
    { value: 'ne', label: '不等于' },
    { value: 'in', label: '属于' },
    { value: 'notIn', label: '不属于' },
  ],
  date: [
    { value: 'eq', label: '等于' },
    { value: 'ne', label: '不等于' },
    { value: 'gt', label: '之后' },
    { value: 'gte', label: '不早于' },
    { value: 'lt', label: '之前' },
    { value: 'lte', label: '不晚于' },
    { value: 'between', label: '介于' },
  ],
  'date-range': [
    { value: 'between', label: '介于' },
    { value: 'notBetween', label: '不在范围' },
  ],
}

const ViewAdvancedFilter: React.FC<ViewAdvancedFilterProps> = ({
  modelId,
  fields = [],
  maxRules = 10,
  collapsible = true,
  defaultCollapsed = false,
  showFieldSelector = true,
  className = '',
  onFilterChange,
}) => {
  const { filters, setFilters, doFilter } = useModelQuery()
  const { getFields } = useModelFields()

  const [rules, setRules] = useState<FilterRule[]>([])
  const [logicOperator, setLogicOperator] = useState<LogicOperator>('AND')
  const [open, setOpen] = useState(!defaultCollapsed)
  const [modelFields, setModelFields] = useState<FilterField[]>(fields)

  React.useEffect(() => {
    if (modelId && fields.length === 0) {
      const loadFields = async () => {
        const schema = await getFields(modelId)
        if (schema) {
          const convertedFields: FilterField[] = schema.map((field: any) => ({
            name: field.name,
            label: field.label || field.name,
            type: field.type || 'text',
            options: field.options,
          }))
          setModelFields(convertedFields)
        }
      }
      loadFields()
    }
  }, [modelId, fields, getFields])

  const addRule = () => {
    if (rules.length >= maxRules) return
    const newRule: FilterRule = {
      id: `rule-${Date.now()}`,
      field: modelFields[0]?.name || '',
      operator: 'eq',
      value: '',
    }
    setRules([...rules, newRule])
  }

  const removeRule = (id: string) => {
    setRules(rules.filter((rule) => rule.id !== id))
  }

  const updateRule = (id: string, updates: Partial<FilterRule>) => {
    setRules(rules.map((rule) => (rule.id === id ? { ...rule, ...updates } : rule)))
  }

  const applyFilter = () => {
    const validRules = rules.filter((rule) => rule.field && rule.operator)
    setFilters({ rules: validRules, logicOperator })
    doFilter()
    onFilterChange?.(validRules, logicOperator)
  }

  const resetFilter = () => {
    setRules([])
    setFilters({})
    doFilter()
  }

  const getFieldType = (fieldName: string): FilterFieldType => {
    const field = modelFields.find((f) => f.name === fieldName)
    return field?.type || 'text'
  }

  const renderValueInput = (rule: FilterRule) => {
    const fieldType = getFieldType(rule.field)
    const field = modelFields.find((f) => f.name === rule.field)

    if (rule.operator === 'empty' || rule.operator === 'notEmpty') {
      return null
    }

    if (rule.operator === 'between' || rule.operator === 'notBetween') {
      return (
        <div className="flex gap-2">
          <Input
            type={fieldType === 'number' ? 'number' : fieldType === 'date' || fieldType === 'date-range' ? 'date' : 'text'}
            value={rule.value || ''}
            onChange={(e) => updateRule(rule.id, { value: e.target.value })}
            placeholder="起始值"
            className="h-8"
          />
          <Input
            type={fieldType === 'number' ? 'number' : fieldType === 'date' || fieldType === 'date-range' ? 'date' : 'text'}
            value={rule.value2 || ''}
            onChange={(e) => updateRule(rule.id, { value2: e.target.value })}
            placeholder="结束值"
            className="h-8"
          />
        </div>
      )
    }

    if (fieldType === 'select' && field?.options) {
      return (
        <Select
          value={rule.value || ''}
          onValueChange={(value) => updateRule(rule.id, { value })}
        >
          <SelectTrigger className="h-8">
            <SelectValue placeholder="选择值" />
          </SelectTrigger>
          <SelectContent>
            {field.options.map((option) => (
              <SelectItem key={option.value} value={option.value}>
                {option.label}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      )
    }

    return (
      <Input
        type={fieldType === 'number' ? 'number' : fieldType === 'date' || fieldType === 'date-range' ? 'date' : 'text'}
        value={rule.value || ''}
        onChange={(e) => updateRule(rule.id, { value: e.target.value })}
        placeholder={field?.placeholder || '输入值'}
        className="h-8"
      />
    )
  }

  const content = (
    <Card className={className}>
      <CardHeader className="pb-3">
        <div className="flex items-center justify-between">
          <CardTitle className="text-base flex items-center gap-2">
            <Filter className="w-4 h-4" />
            高级筛选
          </CardTitle>
          <div className="flex items-center gap-2">
            {rules.length > 0 && (
              <Badge variant="secondary">{rules.length} 条规则</Badge>
            )}
            <Select value={logicOperator} onValueChange={(v: LogicOperator) => setLogicOperator(v)}>
              <SelectTrigger className="h-8 w-20">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="AND">AND</SelectItem>
                <SelectItem value="OR">OR</SelectItem>
              </SelectContent>
            </Select>
          </div>
        </div>
      </CardHeader>
      <CardContent className="space-y-3">
        {rules.length === 0 ? (
          <div className="text-center text-sm text-slate-500 py-4">
            点击下方按钮添加筛选规则
          </div>
        ) : (
          <div className="space-y-3">
            {rules.map((rule) => {
              const fieldType = getFieldType(rule.field)
              const operators = operatorOptions[fieldType] || operatorOptions.text

              return (
                <div key={rule.id} className="flex gap-2 items-start">
                  {showFieldSelector && (
                    <Select
                      value={rule.field}
                      onValueChange={(value) => updateRule(rule.id, { field: value, operator: 'eq', value: '', value2: '' })}
                    >
                      <SelectTrigger className="h-8 w-32">
                        <SelectValue placeholder="选择字段" />
                      </SelectTrigger>
                      <SelectContent>
                        {modelFields.map((field) => (
                          <SelectItem key={field.name} value={field.name}>
                            {field.label}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  )}

                  <Select
                    value={rule.operator}
                    onValueChange={(value) => updateRule(rule.id, { operator: value, value: '', value2: '' })}
                  >
                    <SelectTrigger className="h-8 w-32">
                      <SelectValue placeholder="操作符" />
                    </SelectTrigger>
                    <SelectContent>
                      {operators.map((op) => (
                        <SelectItem key={op.value} value={op.value}>
                          {op.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>

                  <div className="flex-1">
                    {renderValueInput(rule)}
                  </div>

                  <Button
                    variant="ghost"
                    size="icon"
                    className="h-8 w-8"
                    onClick={() => removeRule(rule.id)}
                  >
                    <Trash2 className="w-4 h-4" />
                  </Button>
                </div>
              )
            })}
          </div>
        )}

        <div className="flex gap-2 pt-2">
          <Button
            size="sm"
            onClick={addRule}
            disabled={rules.length >= maxRules}
            className="flex-1"
          >
            <Plus className="w-4 h-4 mr-1" />
            添加规则
          </Button>
          <Button
            size="sm"
            variant="outline"
            onClick={resetFilter}
            disabled={rules.length === 0}
          >
            重置
          </Button>
          <Button
            size="sm"
            onClick={applyFilter}
            disabled={rules.length === 0}
          >
            应用筛选
          </Button>
        </div>
      </CardContent>
    </Card>
  )

  if (collapsible) {
    return (
      <Collapsible open={open} onOpenChange={setOpen}>
        <CollapsibleTrigger asChild>
          <Button variant="outline" className="w-full mb-2">
            {open ? (
              <>
                <ChevronUp className="w-4 h-4 mr-2" />
                收起高级筛选
              </>
            ) : (
              <>
                <ChevronDown className="w-4 h-4 mr-2" />
                展开高级筛选
                {rules.length > 0 && (
                  <Badge variant="secondary" className="ml-2">
                    {rules.length}
                  </Badge>
                )}
              </>
            )}
          </Button>
        </CollapsibleTrigger>
        <CollapsibleContent>
          {content}
        </CollapsibleContent>
      </Collapsible>
    )
  }

  return content
}

export default ViewAdvancedFilter

import React, { useState } from 'react'
import { pick, omit, find, isNil, isEmpty } from 'lodash'
import { useModelDelete, useModelSave, useModelGetItems, useModel, useModelSelect, useModelCallback } from '@airiot/client'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
  DialogTrigger,
  DialogClose,
} from '@/components/ui/dialog'
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu'
import { Button } from '@/components/ui/button'
import { ScrollArea, ScrollBar } from '@/components/ui/scroll-area'
import { Badge } from '@/components/ui/badge'
import { Loader2, Trash2, Edit } from 'lucide-react'
import SchemaForm from '@/registry/blocks/form/schema-form/schema-form'

// ==================== Content Components ====================
// 这些组件只有在 Dialog 打开时才会渲染，从而触发数据加载

interface BatchDeleteContentProps {
  onClose?: () => void
}

const BatchDeleteContent: React.FC<BatchDeleteContentProps> = ({
  onClose
}) => {
  const { deleteItem } = useModelDelete()
  const { getItems } = useModelGetItems()
  const { selected } = useModelSelect<{ id: string, [key: string]: any }>()
  const { model } = useModel()
  const [deleting, setDeleting] = useState(false)

  const handleDelete = async () => {
    setDeleting(true)
    try {
      // 批量删除
      await Promise.all(selected.map(item => deleteItem(item.id)))
      // 刷新列表
      await getItems()
      onClose?.()
    } finally {
      setDeleting(false)
    }
  }

  return (
    <>
      <DialogHeader>
        <DialogTitle>确认批量删除</DialogTitle>
      </DialogHeader>

      <div className="space-y-4 py-4">
        <div className="text-sm text-slate-600">
          确定要删除选中的 <Badge variant="destructive">{selected.length}</Badge> 项数据吗？此操作不可撤销。
        </div>

        {selected && selected.length > 0 && (
          <ScrollArea className="max-h-[60vh] border rounded-lg">
            <div className="p-4 space-y-2 pr-4">
              {selected.map((item) => (
                <div key={item.id} className="flex items-center gap-2 p-2 hover:bg-slate-50 rounded">
                  <div className="flex-1">
                    {model.displayField && item[model.displayField] || item._label || item.name || item.id}
                  </div>
                </div>
              ))}
            </div>
            <ScrollBar orientation="horizontal" />
          </ScrollArea>
        )}
      </div>

      <DialogFooter>
        <DialogClose asChild>
          <Button variant="outline" disabled={deleting}>
            取消
          </Button>
        </DialogClose>
        <Button variant="destructive" onClick={handleDelete} disabled={deleting}>
          {deleting && <Loader2 className="h-4 w-4 animate-spin mr-2" />}
          确认删除
        </Button>
      </DialogFooter>
    </>
  )
}

interface BatchChangeContentProps {
  onClose?: () => void
}

const BatchChangeContent: React.FC<BatchChangeContentProps> = ({
  onClose
}) => {
  const { model } = useModel()
  const { saveItem } = useModelSave()
  const { getItems } = useModelGetItems()
  const { selected } = useModelSelect<{ id: string, [key: string]: any }>()
  const [saving, setSaving] = useState(false)
  const fields = (model.batchChangeFields || ['name', 'money']) as string[]
  const fs = fields.map(f => f.split('.')[0])
  const formSchema = model.form !== undefined ? fs.map(name => find(model.form, f => f && (f == name || f.key == name || f.name == name)) || name) : ['*']
  const formId = `batch-change-form-${Date.now()}`

  const handleSubmit = useModelCallback(async (_get, set, atoms, values: any) => {
    setSaving(true)
    try {
      // 批量修改：传递 ids 和要修改的字段值
      let ret = await Promise.all(selected.map(item => saveItem({ id: item.id, ...values }, true)))
      // 刷新列表
      if(isNil(ret) || isEmpty(ret)) {
        getItems()
      } else {
        ret.forEach(item => set(atoms.item(item.id), item))
      }
      onClose?.()
    } finally {
      setSaving(false)
    }
  }, [selected, saveItem, getItems, onClose])

  return (
    <>
      <DialogHeader>
        <DialogTitle>批量修改</DialogTitle>
      </DialogHeader>

      <div className="space-y-4 py-4">
        <div className="text-sm text-slate-600">
          已选择 <Badge variant="secondary">{selected.length}</Badge> 项数据，请输入要修改的字段值。
        </div>

        <ScrollArea className="max-h-[60vh] pr-3">
          <SchemaForm
            formId={formId}
            schema={omit({
              ...model,
              properties: pick(model.properties, fs),
              form: formSchema
            }, 'required')}
            formSchema={formSchema}
            onSubmit={handleSubmit}
          />
          <ScrollBar orientation="horizontal" />
        </ScrollArea>
      </div>

      <DialogFooter>
        <DialogClose asChild>
          <Button variant="outline" disabled={saving}>
            取消
          </Button>
        </DialogClose>
        <Button form={formId} type="submit" disabled={saving}>
          {saving && <Loader2 className="h-4 w-4 animate-spin mr-2" />}
          确认修改
        </Button>
      </DialogFooter>
    </>
  )
}

