  const isDisabled = disabled || selected.length === 0

  // Render as button group
  if (variant === 'buttons') {
    return (
      <div className="flex items-center gap-2">
        {selected.length > 0 && (
          <Badge variant="secondary" className="text-xs">
            已选 {selected.length} 项
