import React, { useEffect, useMemo, useState } from 'react';
import { useModelList, useModel, useModelSelect, useModelState, type ModelSchema } from '@airiot/client'
import { DataGrid } from '@/components/ui/data-grid';
import { DataGridColumnHeader } from '@/components/ui/data-grid-column-header';
import { DataGridTable,
  DataGridTableRowSelect,
  DataGridTableRowSelectAll, } from '@/components/ui/data-grid-table';
import { ScrollArea, ScrollBar } from '@/components/ui/scroll-area';
import ViewField from "@/registry/blocks/view/view-field/view-field"
import {
  type ColumnDef, type TableOptions, type CellContext, type SortingState, type RowSelectionState,
  getCoreRowModel,
  getSortedRowModel,
  useReactTable,
  createColumnHelper,
} from '@tanstack/react-table';
import { cn } from '@/lib/utils';
import { set } from 'lodash';

interface IData {
  id: string;
  [key: string]: any;
}

type ColumnFieldDef = ColumnDef<IData> & {
  postion?: 'left' | 'right';
  remove: boolean;
}

export interface TableLayoutProps {
  border?: boolean;
  dense?: boolean;
  cellBorder?: boolean;
  rowBorder?: boolean;
  rowRounded?: boolean;
  stripped?: boolean;
  headerBackground?: boolean;
  headerBorder?: boolean;
  headerSticky?: boolean;
  width?: 'auto' | 'fixed';
  layout?: 'auto' | 'fixed';
  columnsVisibility?: boolean;
  columnsResizable?: boolean;
  columnsPinnable?: boolean;
  columnsMovable?: boolean;
  columnsDraggable?: boolean;
  rowsDraggable?: boolean;
}

const getFieldProp = (model: ModelSchema | null | undefined, field: string): any => {
  if (!model) return undefined
  return field.split('.').reduce((obj: any, f: string) => {
    return obj && obj.properties && obj.properties[f]
  }, model)
}

const DataCell = ({ name, type, children, ...restProps }: 
  {name: string, type?: string, 
    children?: React.ReactNode | ((props: any) => React.ReactNode), [key: string]: any}) => 
  ({ getValue, row }: CellContext<IData, any>) => {
  return <ViewField name={name} type={type} value={getValue()} item={row.original} {...restProps}>{children}</ViewField>
}

export const DataTable = ({
  data,
  columns=[],
  className,
  tableLayout = {},
  tableOptions = {},
  gridOptions = {},
  children
}: {
  data: IData[],
  className?: string,
  tableLayout?: TableLayoutProps,
  tableOptions?: Omit<TableOptions<IData>, 'data' | 'columns' | 'getCoreRowModel'>,
  columns?: ColumnDef<IData>[]
  gridOptions: Omit<React.ComponentProps<typeof DataGrid>, 'table' | 'recordCount' | 'tableLayout'>
  children?: React.ReactElement[] | undefined
}) => {
  const { withColumns, getColumns } = useTableContainer(children);
  const defColumns: ColumnDef<IData>[] = getColumns();
  const columnsFinal = [] as ColumnDef<IData>[];

  columns.forEach(column => {
    const defColumn = defColumns.find(col => col.id === column.id);
    if(defColumn) {
      Object.assign(column, defColumn)
      defColumns.splice(defColumns.indexOf(defColumn), 1)
    }
    columnsFinal.push(column);
  })
  defColumns.forEach(col => {
      columnsFinal.push(col);
  })

  const table = useReactTable({
    columns: columnsFinal,
    data: data,
    getRowId: (row: IData) => row.id,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    columnResizeMode: 'onChange',
    ...tableOptions,
  });

  // 合并默认 tableLayout 和传入的 tableLayout
  const defaultTableLayout: TableLayoutProps = {
    border: true,
    columnsResizable: true,
    columnsPinnable: true,
    headerSticky: true,
    rowBorder: true,
    cellBorder: false,
    headerBorder: true,
    width: 'fixed'
  }

  const mergedTableLayout = { ...defaultTableLayout, ...tableLayout }

  return withColumns(
    <DataGrid table={table} recordCount={data?.length || 0}
      tableLayout={mergedTableLayout}
      {...gridOptions}>
      <div data-slot="data-grid" className={cn('w-full', mergedTableLayout.border && 'border border-border rounded-lg', className)}>
        <ScrollArea>
          <DataGridTable />
          <ScrollBar orientation="horizontal" />
        </ScrollArea>
      </div>
    </DataGrid>
  );
}

export function ViewDataTable({
  className,
  tableLayout = {},
  tableOptions = {},
  gridOptions = {},
  children
}: {
  className?: string,
  tableLayout?: TableLayoutProps,
  tableOptions?: Omit<TableOptions<IData>, 'data' | 'columns' | 'getCoreRowModel'>,
  columns?: ColumnDef<IData>[]
  gridOptions?: Omit<React.ComponentProps<typeof DataGrid>, 'table' | 'recordCount' | 'tableLayout'>
  children?: React.ReactElement[] | undefined
}) {
  const { items, loading, fields } = useModelList()
  const { model, atoms } = useModel()

  const [ rowSelection, setRowSelection] = useState<RowSelectionState>({});
  const [ selected, setSelected ] = useModelState<{id: string}[]>(atoms.selected)

  const [ order, setOrder ] = useModelState(atoms.order)
  const [ sorting, setSorting ] = useState<SortingState>([])

  const lockedFields = model.lockedFields || []
  const columnHelper = createColumnHelper<IData>()
  const columns: ColumnDef<IData>[] = []

  fields.forEach((fieldName)=> {
    const field = getFieldProp(model, fieldName)
    if(!field) return
    const column: ColumnDef<IData> = columnHelper.accessor(fieldName, {
      id: fieldName,
      field,
      size: field.width || undefined,
      fixed: lockedFields.indexOf(fieldName) >= 0,
      header: ({ column }) => <DataGridColumnHeader title={field.title || fieldName} column={column} />,
      cell: DataCell({ name: fieldName, type: field.type as string, ...field.column }),
      ...field.column
    })

    if(field.level2) {
      const lastColumn = columns[columns.length - 1] as any
      if(lastColumn && lastColumn.columns !== undefined &&
        lastColumn.header == field.level2 ) {
        lastColumn.columns.push(column)
      } else {
        columns.push({
          header: field.level2,
          columns: [ column ]
        })
      }
    } else {
      columns.push(column)
    }
  })

  // 配置行选择
  const onRowSelectionChange = (handler: (state: RowSelectionState) => RowSelectionState) => {
    const newSelection = handler(rowSelection)
    setSelected(items.filter(item => newSelection[item.id]));
  }

  useEffect(() => {
    setRowSelection(selected.reduce((obj: Record<string, boolean>, item: any) => {
      obj[item.id] = true;
      return obj;
    }, {}));
  }, [ selected ]);

  columns.unshift({
    accessorKey: 'id',
    header: () => <DataGridTableRowSelectAll />,
    cell: ({ row }) => <DataGridTableRowSelect row={row} />,
    enableSorting: false,
    size: 35,
    meta: {
      headerClassName: '',
      cellClassName: '',
    },
  })

  // 配置排序
  const onSortingChange = (handler: (state: SortingState) => SortingState) => {
    const newSorting = handler(sorting)
    // 转换为 order 格式
    const newOrder: Record<string, 'asc' | 'desc'> = {}
    newSorting.forEach(sort => {
      newOrder[sort.id] = sort.desc ? 'desc' : 'asc'
    })
    // 更新模型状态
    setOrder(newOrder)
  }

  useEffect(() => {
    setSorting(Object.keys(order || {}).map(key => ({
      id: key,
      desc: order ? order[key] === 'desc' : false,
      asc: order ? order[key] === 'asc' : false
    })));
  }, [order]);

  const tableProps = model.dataTableProps ? (
    typeof model.dataTableProps == 'function' ?
      model.dataTableProps(columns, items) : model.dataTableProps
  ) : {}

  return <DataTable
    data={items as IData[]}
    columns={columns}
    className={className}
    tableLayout={tableLayout}
    gridOptions={{
      ...gridOptions,
      isLoading: loading
    }}
    tableOptions={{
      ...tableProps,
      ...tableOptions,
      initialState: {
        ...tableOptions.initialState,
        columnPinning: {
          right: ['__actions__'],
        },
      },
      // 添加行选择配置
      ...({ onRowSelectionChange, enableRowSelection: true, }),
      // 添加排序配置
      state: {
        ...(tableOptions.state || {}),
        sorting,
        rowSelection
      },
      onSortingChange
    }}
  >{children}</DataTable>;
}

// TableColumn 组件 - 用于定义和配置列
interface TableColumnProps {
  name: string;
  title?: string;
  width?: number;
  fixed?: boolean | 'left' | 'right';
  header?: React.ReactNode;
  cell?: React.ReactNode;
  type?: string;
  level2?: string;
  children?: React.ReactNode | ((props: any) => React.ReactNode);
  [key: string]: any;
}

interface ColumnContextValue {
  columns: Map<string, ColumnDef<IData>>;
  setColumn: (name: string, column: ColumnDef<IData>) => void;
  getColumn: (name: string) => ColumnDef<IData> | undefined;
  getColumns: () => ColumnDef<IData>[];
}

const ColumnContext = React.createContext<ColumnContextValue | null>(null);

const useTableContainer = (children: React.ReactElement[] | undefined) => {
  const columns = React.useRef<Map<string, ColumnDef<IData>>>(new Map());
  const [inited, setInited] = React.useState<boolean>(false);

  // 设置列
  const setColumn = (name: string, column: ColumnDef<IData>) => {
    columns.current.set(name, column);
  };

  // 获取单个列
  const getColumn = (name: string): ColumnDef<IData> | undefined => {
    return columns.current.get(name);
  };

  // 获取所有列（按定义顺序）
  const getColumns = (): ColumnDef<IData>[] => {
    return Array.from(columns.current.values());
  };

  const contextValue: ColumnContextValue = {
    columns: columns.current,
    setColumn,
    getColumn,
    getColumns,
  };

  React.useEffect(() => {
    if(!inited)
      setInited(true);
  }, []);

  const withColumns = React.useCallback((table: React.ReactElement) => (
    <ColumnContext.Provider value={contextValue}>
      {useMemo(() => children, [])}
      {inited && table}
    </ColumnContext.Provider>
  ), [ children, contextValue, inited])

  return { withColumns, getColumns };
}

export const TableColumn: React.FC<TableColumnProps> = ({
  name,
  title,
  width,
  fixed,
  header,
  cell,
  type,
  level2,
  children,
  ...columnProps
}) => {
  const columnContext = React.useContext(ColumnContext);

  if (!columnContext) {
    console.warn('TableColumn must be used within DataTableContainer');
    return null;
  }

  React.useEffect(() => {
    const columnDef: ColumnDef<IData> = {
      id: name,
      accessorKey: name,
      header: header ? header as any : (({ column }) => <DataGridColumnHeader title={title || name} column={column as any} />),
      cell: cell ? cell as any : DataCell({ name, type, children }),
      size: width as number | undefined,
      ...columnProps
    };

    columnContext.setColumn(name, columnDef);
  }, [name, title, type, children, width, fixed, header, cell, level2, columnContext, columnProps]);

  return null;
};

export default ViewDataTable;

import React, { useState } from 'react'
import { useModelItem, useModelGet, useModel, useFormSchema } from '@airiot/client'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
  DialogTrigger,
  DialogClose
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { ScrollArea, ScrollBar } from '@/components/ui/scroll-area'
import { Badge } from '@/components/ui/badge'
import { Separator } from '@/components/ui/separator'
import { Loader2 } from 'lucide-react'

interface ViewDetailProps {
  modelId?: string
  itemId?: string
  fields?: Array<{
    key: string
    label: string
    type?: 'text' | 'number' | 'date' | 'boolean' | 'json'
    render?: (value: any, record: any) => React.ReactNode
  }>
  size?: 'sm' | 'md' | 'lg' | 'xl' | 'full'
  readonly?: boolean
  trigger?: React.ReactNode
  open?: boolean
  onOpenChange?: (open: boolean) => void
}

const ViewDetail: React.FC<ViewDetailProps> = ({
  itemId,
  size = 'lg',
  trigger,
  open: controlledOpen,
  onOpenChange
}) => {
  const [internalOpen, setInternalOpen] = useState(false)
  const isOpen = controlledOpen !== undefined ? controlledOpen : internalOpen
  const { title, data, loading, model } = useModelGet({ id: itemId })
  const { fields } = useFormSchema({ schema: model })

  // 渲染字段值
  const renderValue = (field: any, record: any) => {
    const value = record?.[field.key]

    if (field.render) {
      return field.render(value, record)
    }

    if (field.type === 'boolean') {
      return value ? (
        <Badge variant="outline" className="bg-green-50 text-green-700 border-green-200">
          是
        </Badge>
      ) : (
        <Badge variant="outline" className="bg-slate-50 text-slate-700 border-slate-300">
          否
        </Badge>
      )
    }

    if (field.type === 'date') {
      return value ? new Date(value).toLocaleString('zh-CN') : '-'
    }

    if (field.type === 'json') {
      return (
        <pre className="text-xs bg-slate-100 p-2 rounded overflow-auto max-h-32">
          {JSON.stringify(value, null, 2)}
        </pre>
      )
    }

    if (field.type === 'number') {
      return value?.toLocaleString() ?? '-'
    }

    return value || '-'
  }

  const content = (
    <DialogContent className={size}>
      <DialogHeader>
        <DialogTitle>{title}</DialogTitle>
      </DialogHeader>
      {loading ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="h-6 w-6 animate-spin text-primary" />
        </div>
      ) : data ? (
        <ScrollArea className="max-h-[70vh]">
          <div className="space-y-4 pr-4">
            {fields.map((field, index) => (
              <div key={field.key} className="space-y-1">
                <div className="flex items-center justify-between">
                  <label className="text-sm font-medium text-slate-700">
                    {field.label}
                  </label>
                </div>
                <div className="text-sm text-slate-900">
                  {renderValue(field, data)}
                </div>
                {index < fields.length - 1 && (
                  <Separator className="mt-4" />
                )}
              </div>
            ))}
          </div>
          <ScrollBar orientation="horizontal" />
        </ScrollArea>
      ) : (
        <div className="flex items-center justify-center py-12 text-slate-500">
          暂无数据
        </div>
      )}

      <DialogFooter>
        <DialogClose asChild>
          <Button
            variant="outline"
          >
            关闭
          </Button>
        </DialogClose>
      </DialogFooter>
    </DialogContent>
  )

  if (trigger) {
    return (
    <Dialog>
      <DialogTrigger asChild>
        {trigger}
      </DialogTrigger>
      {content}
    </Dialog>
    )
  }

  return (
    <Dialog open={isOpen} onOpenChange={onOpenChange || setInternalOpen}>
      {content}
    </Dialog>
  )
}

export default ViewDetail

import React from 'react'
import dayjs from 'dayjs'

const Text = ({ value }: { value: any }) => value

const ArrayData = ({ value }: { value: any }) => {
  if (Array.isArray(value)) {
    return value.join(', ')
  }
  return '-'
}

const Textarea = ({ value }: { value: any }) => (
  <div className="whitespace-pre-wrap">{value}</div>
)

const Number = ({ value }: { value: any }) => value

const Select = ({ value, options }: { value: any, options?: any[] }) => {
  const selected = options?.find((opt: any) => opt.value === value)
  return selected ? selected.label : value
}

const Checkbox = ({ value }: { value: any }) => (
  <span>{value ? '✓' : '✗'}</span>
)

const Radio = ({ value, options }: { value: any, options?: any[] }) => {
  const selected = options?.find((opt: any) => opt.value === value)
  return selected ? selected.label : value
}

const Switch = ({ value }: { value: any }) => (
  <span className={value ? 'text-green-600' : 'text-gray-400'}>
    {value ? '开' : '关'}
  </span>
)

const Slider = ({ value, min, max }: { value: any, min?: number, max?: number }) => (
  <div className="flex items-center gap-2">
    <div className="flex-1 h-2 bg-gray-200 rounded-full">
      <div
        className="h-2 bg-blue-500 rounded-full"
        style={{ width: `${((value - (min || 0)) / ((max || 100) - (min || 0))) * 100}%` }}
      />
    </div>
    <span className="text-sm text-gray-600">{value}</span>
  </div>
)

const Date = ({ value, format }: { value: any, format?: string }) => {
  if (!value) return '-'
  return dayjs(value).format(format || 'YYYY-MM-DD')
}

const Rate = ({ value, max }: { value: any, max?: number }) => {
  const maxStars = max || 5
  return (
    <div className="flex gap-1">
      {Array.from({ length: maxStars }).map((_, i) => (
        <span
          key={i}
          className={i < value ? 'text-yellow-400' : 'text-gray-300'}
        >
          ★
        </span>
      ))}
    </div>
  )
}

const fieldMap: { [key: string]: React.ComponentType<any> } = {
  'text': Text,
  'array': ArrayData,
  'textarea': Textarea,
  'number': Number,
  'select': Select,
  'checkbox': Checkbox,
  'radio': Radio,
  'switch': Switch,
  'slider': Slider,
  'date': Date,
  'rate': Rate
}

export default fieldMap

import {
  Field,
  FieldDescription,
  FieldLabel
} from "@/components/ui/field"
import type { ReactNode } from 'react'
import React, { cloneElement } from 'react'
import fieldMap from './field-map'

type ViewFieldProps = {
  name: string
  value: any
  item: any
  type?: string
  schema?: any
  label?: ReactNode | string
  description?: ReactNode | string
  children?: ReactNode | ((props: any) => ReactNode)
  [key: string]: any
}

const Text = ({ value }: { value: any }) => value

const ViewField = ({ name, label, type, description, children, value, item, ...restProps }: ViewFieldProps) => {
  const ValueComponent = (type && fieldMap[type] || Text) as React.ComponentType<any>

  const fieldValue = (
    children ? ( typeof children === 'function' ? children({
      name, value, item,
      ...restProps
    }) : cloneElement(children as React.ReactElement<any>, {
      name,
      value, item,
      ...restProps
    }) ) : (
      <ValueComponent
        name={name}
        value={value}
        item={item}
        {...restProps}
      />
    )
  )

  return (label || description) ?(
    <Field>
      {label && <FieldLabel>
        {label}
      </FieldLabel>}
      {fieldValue}
      {description && (
        <FieldDescription>
          {description}
        </FieldDescription>
      )}
    </Field>
  ) : fieldValue
}

