import React, { useState } from 'react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { useModel, useModelList, useModelQuery } from '@airiot/client'
import { Search, X, Filter } from 'lucide-react'

interface ViewFilterProps {
  modelId?: string
  fields?: Array<{
    key: string
    label: string
    type?: 'text' | 'number' | 'select' | 'date'
    options?: Array<{ label: string; value: any }>
  }>
  inline?: boolean
  collapsible?: boolean
  className?: string
}

interface FilterValue {
  [key: string]: any
}

const ViewFilter: React.FC<ViewFilterProps> = ({
  modelId,
  fields = [],
  inline = false,
  collapsible = false,
  className = ''
}) => {
  const { filters, setFilters, doFilter } = useModelQuery()
  const [collapsed, setCollapsed] = useState(false)
  const [localFilters, setLocalFilters] = useState<FilterValue>({})

  // 处理筛选条件变化
  const handleFilterChange = (key: string, value: any) => {
    setLocalFilters(prev => ({
      ...prev,
      [key]: value
    }))
  }

  // 清除单个筛选条件
  const handleClearFilter = (key: string) => {
    setLocalFilters(prev => {
      const newFilters = { ...prev }
      delete newFilters[key]
      return newFilters
    })
  }

  // 应用筛选
  const handleApplyFilter = () => {
    setFilters(localFilters)
    doFilter()
  }

  // 重置所有筛选
  const handleResetFilter = () => {
    setLocalFilters({})
    setFilters({})
    doFilter()
  }

  // 是否有激活的筛选条件
  const hasActiveFilters = Object.keys(localFilters).length > 0

  if (collapsed) {
    return (
      <div className={`flex items-center gap-2 ${className}`}>
        <Button
          variant="outline"
          size="sm"
          onClick={() => setCollapsed(false)}
        >
          <Filter className="h-4 w-4 mr-2" />
          筛选
          {hasActiveFilters && (
            <span className="ml-1 px-2 py-0.5 bg-primary text-primary-foreground text-xs rounded-full">
              {Object.keys(localFilters).length}
            </span>
          )}
        </Button>
      </div>
    )
  }

  return (
    <div className={`space-y-4 ${className}`}>
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Filter className="h-4 w-4 text-slate-600" />
          <h3 className="text-sm font-semibold text-slate-900">筛选条件</h3>
          {hasActiveFilters && (
            <span className="px-2 py-0.5 bg-primary text-primary-foreground text-xs rounded-full">
              {Object.keys(localFilters).length}
            </span>
          )}
        </div>
        {collapsible && (
          <Button
            variant="ghost"
            size="sm"
            onClick={() => setCollapsed(true)}
          >
            收起
          </Button>
        )}
      </div>

      <div className={`${inline ? 'flex flex-wrap gap-4 items-end' : 'space-y-4'}`}>
        {fields.map((field) => (
          <div key={field.key} className={`${inline ? 'flex-1 min-w-[200px]' : ''}`}>
            <Label htmlFor={`filter-${field.key}`} className="text-sm text-slate-700">
              {field.label}
            </Label>
            {field.type === 'select' && field.options ? (
              <select
                id={`filter-${field.key}`}
                value={localFilters[field.key] || ''}
                onChange={(e) => handleFilterChange(field.key, e.target.value)}
                className="w-full px-3 py-2 border border-slate-300 rounded-md text-sm focus:outline-none focus:ring-2 focus:ring-primary"
              >
                <option value="">全部</option>
                {field.options.map((option) => (
                  <option key={option.value} value={option.value}>
                    {option.label}
                  </option>
                ))}
              </select>
            ) : field.type === 'date' ? (
              <Input
                id={`filter-${field.key}`}
                type="date"
                value={localFilters[field.key] || ''}
                onChange={(e) => handleFilterChange(field.key, e.target.value)}
                className="w-full"
              />
            ) : (
              <Input
                id={`filter-${field.key}`}
                type={field.type === 'number' ? 'number' : 'text'}
                value={localFilters[field.key] || ''}
                onChange={(e) => handleFilterChange(field.key, e.target.value)}
                placeholder={`请输入${field.label}`}
                className="w-full"
              />
            )}
          </div>
        ))}
      </div>

      <div className="flex items-center gap-2">
        <Button
          onClick={handleApplyFilter}
          className="flex items-center gap-2"
        >
          <Search className="h-4 w-4" />
          查询
        </Button>
        <Button
          variant="outline"
          onClick={handleResetFilter}
          disabled={!hasActiveFilters}
          className="flex items-center gap-2"
        >
          <X className="h-4 w-4" />
          重置
        </Button>
      </div>

      {/* 激活的筛选标签 */}
      {hasActiveFilters && (
        <div className="flex flex-wrap gap-2 pt-2 border-t border-slate-200">
          {Object.entries(localFilters).map(([key, value]) => (
            <div
              key={key}
              className="inline-flex items-center gap-1 px-3 py-1 bg-slate-100 rounded-full text-sm"
            >
              <span className="text-slate-700">
                {fields.find(f => f.key === key)?.label || key}: {value}
              </span>
              <button
                onClick={() => handleClearFilter(key)}
                className="ml-1 text-slate-500 hover:text-slate-700"
              >
                <X className="h-3 w-3" />
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

export default ViewFilter

import React from 'react'
import { TableModel, Model } from '@airiot/client'

interface TableFilter {
  [key: string]: any
}

interface TableRef {
  id: string | number
  [key: string]: any
}

type TableViewProps = {
  tableId?: string
  modelName?: string
  loadingComponent?: React.ReactNode, 
  initQuery?: boolean, 
  children?: React.ReactNode
  table?: TableRef

  queryFields?: string[]
  projectAll?: boolean
  limit?: number
  tableFilters?: TableFilter[]
  fieldOrder?: Record<string, 'asc' | 'desc'>[]
  interval?: number
}

const TableView = ({ tableId, modelName, children, initQuery, loadingComponent,
  queryFields, projectAll,
  limit,
  tableFilters,
  fieldOrder,
  interval
 }: TableViewProps) => {
  const [ initialValues, setInitialValues ] = React.useState<any | null>(null)

  React.useEffect(() => {
    const values = {} as any
    if (queryFields && queryFields.length > 0) {
      values['fields'] = queryFields
    }
    if (projectAll) {
      values['projectAll'] = true
    }
    if (limit) {
      values['limit'] = limit
    }
    if (tableFilters && tableFilters.length > 0) {
      values['wheres'] = { tableFilters }
    }
    if (fieldOrder && fieldOrder.length > 0) {
      values['order'] = fieldOrder
    }
    setInitialValues(values)
  }, [queryFields, projectAll, limit, tableFilters, fieldOrder, interval])

  if(initialValues === null) {
    return null
  } else if (modelName) {
    return (
      <Model name={modelName} key={`table-model-view-${modelName}`} initialValues={initialValues}>
        {children}
      </Model>
    )
  } else if (tableId) {
    return (
      <TableModel tableId={tableId} key={`table-model-view-${tableId}`} loadingComponent={loadingComponent} initQuery={initQuery} initialValues={initialValues}>
        {children}
      </TableModel>
    )
  } else {
    return null
  }
}

export default TableView

import React from 'react'
import {
  Pagination,
  PaginationContent,
  PaginationItem,
  PaginationLink,
  PaginationEllipsis,
} from '@/components/ui/pagination'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import { ChevronLeft, ChevronRight } from 'lucide-react'
import { useModelPagination, useModelPageSize, useModelCount } from '@airiot/client'

interface ViewPaginationProps {
  showSizeChanger?: boolean
  showQuickJumper?: boolean
  showTotal?: boolean
  pageSizeOptions?: number[]
  className?: string
  disabled?: boolean
}

const ViewPagination: React.FC<ViewPaginationProps> = ({
  showSizeChanger = false,
  showQuickJumper = true,
  showTotal = false,
  className = '',
  disabled = false
}) => {
  const { items, activePage, changePage } = useModelPagination()
  const { sizes, setPageSize, size } = useModelPageSize()
  const { count } = useModelCount()

  const totalPages = Math.ceil(items) || 1

  // 不显示分页的情况
  // if (totalPages <= 1) {
  //   return null
  // }

  const handlePageChange = (page: number) => {
    if (!disabled) {
      changePage(page)
    }
  }

  const handlePageSizeChange = (newPageSize: number) => {
    if (!disabled) {
      setPageSize(newPageSize)
    }
  }

  // 生成页码
  const getPageNumbers = () => {
    const maxButtons = 7
    const pages: (number | 'ellipsis')[] = []

    if (totalPages <= maxButtons) {
      for (let i = 1; i <= totalPages; i++) {
        pages.push(i)
      }
    } else {
      if (activePage <= Math.ceil(maxButtons / 2)) {
        // 靠近开始
        for (let i = 1; i <= maxButtons - 2; i++) {
          pages.push(i)
        }
        pages.push('ellipsis')
        pages.push(totalPages)
      } else if (activePage >= totalPages - Math.floor(maxButtons / 2)) {
        // 靠近结束
        pages.push(1)
        pages.push('ellipsis')
        for (let i = totalPages - (maxButtons - 2); i <= totalPages; i++) {
          pages.push(i)
        }
      } else {
        // 在中间
        pages.push(1)
        pages.push('ellipsis')
        const start = activePage - Math.floor((maxButtons - 4) / 2)
        for (let i = start; i < start + maxButtons - 4; i++) {
          pages.push(i)
        }
        pages.push('ellipsis')
        pages.push(totalPages)
      }
    }

    return pages
  }

  return (
    <div className={`flex items-center justify-between gap-4 ${className}`}>
      {/* 显示总数 */}
      {showTotal && (
        <div className="text-sm text-slate-600">
          共 {count} 条
        </div>
      )}

      {/* 分页器 */}
      <div className="flex items-center gap-2">
        <Pagination className="gap-1">
          <PaginationContent>
            {/* 上一页 */}
            <PaginationLink
              aria-label="Go to previous page"
              size="default"
              onClick={() => handlePageChange(activePage - 1)}
              isActive={!(disabled || activePage === 1)}
              className="gap-1 pl-2.5 disabled:opacity-50"
            >
              <ChevronLeft className="h-4 w-4" />
              <span>上一页</span>
            </PaginationLink>

            {/* 页码 */}
            {getPageNumbers().map((page, index) => {
              if (page === 'ellipsis') {
                return <PaginationEllipsis key={`ellipsis-${index}`} />
              }

              return (
                <PaginationItem key={page}>
                  <PaginationLink
                    isActive={page === activePage}
                    onClick={() => handlePageChange(page as number)}
                    className="cursor-pointer"
                  >
                    {page}
                  </PaginationLink>
                </PaginationItem>
              )
            })}

            {/* 下一页 */}
            <PaginationLink
              aria-label="Go to next page"
              size="default"
              onClick={() => handlePageChange(activePage + 1)}
              isActive={!(disabled || activePage === totalPages)}
              className="gap-1 pr-2.5 disabled:opacity-50"
            >
              <span>下一页</span>
              <ChevronRight className="h-4 w-4" />
            </PaginationLink>

          </PaginationContent>
        </Pagination>
      </div>

      {/* 每页条数选择器 */}
      {showSizeChanger && (
        <div className="flex items-center gap-2">
          <Select
            value={size.toString()}
            onValueChange={(value) => handlePageSizeChange(Number(value))}
            disabled={disabled}
          >
            <SelectTrigger className="w-[100px]">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              {sizes.map((size) => (
                <SelectItem key={size} value={size.toString()}>
                  {size} 条/页
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      )}

      {/* 快速跳转 */}
      {showQuickJumper && totalPages > 5 && (
        <div className="flex items-center gap-2 text-sm">
          <span className="text-slate-600">跳至</span>
          <input
            type="number"
            min={1}
            max={totalPages}
            className="w-16 px-2 py-1 border border-slate-300 rounded-md text-center disabled:opacity-50"
            disabled={disabled}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                const page = parseInt(e.currentTarget.value)
                if (page >= 1 && page <= totalPages) {
                  handlePageChange(page)
                }
              }
            }}
          />
          <span className="text-slate-600">页</span>
        </div>
      )}
    </div>
  )
}

export default ViewPagination

