        ))}
        <DropdownMenuSeparator />
        <div className="p-2">
          <Input
            placeholder="自定义每页条数"
            type="number"
            value={inputSize}
            onChange={(e) => setInputSize(e.target.value)}
            onKeyDown={handleInputKeyDown}
            min={1}
