      ...props
    },
    ref
  ) => {
    // 内部状态管理（当 open 未受控时使用）
    const [internalOpen, setInternalOpen] = React.useState(false)

    // 表单信息状态（用于与内部表单组件通信）
    const [formInfo, _setFormInfo] = React.useState<{
      handleSubmit?: () => Promise<void>
      submitting?: boolean
      invalid?: boolean
      onReset?: () => void
    }>({})

    // 判断是否受控
    const isControlled = open !== undefined
    const isOpen = isControlled ? open : internalOpen

    // 处理打开/关闭
    const handleOpenChange = (newOpen: boolean) => {
      if (!isControlled) {
        setInternalOpen(newOpen)
      }
      onOpenChange?.(newOpen)
    }

    // 处理保存（支持表单提交）
    const handleSubmit = async () => {
      // 如果有表单提交函数，优先使用表单提交
      if (formInfo?.handleSubmit) {
        await formInfo.handleSubmit()
      }
      // 否则使用自定义 onSubmit
      if (onSubmit) {
        await onSubmit()
      }
      handleOpenChange(false)
    }

    // 处理取消（支持表单重置）
    const handleCancel = () => {
      // 如果有表单重置函数，调用表单重置
      if (formInfo?.onReset) {
        formInfo.onReset()
      }
      // 调用自定义 onCancel
      onCancel?.()
      handleOpenChange(false)
    }

    // 计算样式
    const contentStyle = React.useMemo(() => {
      const style: React.CSSProperties = {}
      if (typeof modalWidth === 'number') {
        style.width = `${modalWidth}px`
      } else if (typeof modalWidth === 'string') {
        style.width = modalWidth
      }

      if (modalHeight) {
        if (typeof modalHeight === 'number') {
          style.maxHeight = `${modalHeight}px`
        } else if (typeof modalHeight === 'string') {
          style.maxHeight = modalHeight
        }
      }

      return style
    }, [modalWidth, modalHeight])

    // Modal Context 值
    const modalContextValue = React.useMemo(() => ({
      open: isOpen,
      setOpen: handleOpenChange,
      showButton: showSubmitButton || showCancelButton,
      formInfo
    }), [isOpen, showSubmitButton, showCancelButton, formInfo])

    return (
      <ModalWigetContext.Provider value={modalContextValue}>
        <Dialog open={isOpen} onOpenChange={handleOpenChange}>
          {showTrigger && (
            <DialogTrigger asChild>
              <Button variant="outline">{triggerText}</Button>
            </DialogTrigger>
          )}
          <DialogContent
            ref={ref}
            className={cn("modal-container", className)}
            style={contentStyle}
            onPointerDownOutside={() => {
              // 阻止点击遮罩关闭（如果需要）
              // event.preventDefault()
            }}
            {...props}
          >
            {(title || description) && (
              <DialogHeader>
                {title && <DialogTitle>{title}</DialogTitle>}
                {description && <DialogDescription>{description}</DialogDescription>}
              </DialogHeader>
            )}

            <div
              className={cn(
                "overflow-auto",
                modalHeight && "flex-1"
              )}
              style={{
                maxHeight: modalHeight ? 'calc(100% - 100px)' : undefined
              }}
            >
              {destroyOnClose && isOpen ? children : !destroyOnClose && children}
            </div>

            {(showSubmitButton || showCancelButton) && (
              <DialogFooter>
                {showCancelButton && (
                  <Button variant="outline" onClick={handleCancel}>
                    {cancelText}
                  </Button>
                )}
                {showSubmitButton && (
                  <Button
                    onClick={handleSubmit}
                    loading={formInfo?.submitting}
                    disabled={formInfo?.invalid}
                  >
                    {submitText}
                  </Button>
                )}
              </DialogFooter>
            )}
          </DialogContent>
        </Dialog>
      </ModalWigetContext.Provider>
    )
  }
)

Modal.displayName = "Modal"

export { Modal }

import * as React from "react"
import { cn } from "@/lib/utils"
import {
  Accordion,
  AccordionItem,
  AccordionTrigger,
  AccordionContent,
} from "@/components/ui/accordion"

export interface PanelConfig {
  /**
   * 面板标题
   */
  title: string
  /**
   * 强制渲染（即使未展开也渲染 DOM）
   */
  forceRender?: boolean
}

export interface PanelProps extends React.HTMLAttributes<HTMLDivElement> {
  /**
   * 是否手风琴模式（只允许一个面板展开）
   * @default true
   */
  accordion?: boolean
  /**
   * 是否允许全部折叠（仅在手风琴模式下有效）
   * @default false
   */
  collapsible?: boolean
  /**
   * 面板配置数组
   */
  panels?: PanelConfig[]
  /**
   * 默认展开的面板索引（从 0 开始）
   * 手风琴模式：单个数字，多开模式：数字数组
   * @default 0
   */
  defaultValue?: number | number[]
  /**
   * 受控模式：当前展开的面板索引
   */
  value?: string | string[]
  /**
   * 展开状态变化回调
   */
  onValueChange?: (value: string | string[]) => void
  /**
   * 子元素（如果提供 panels，则忽略 children）
   */
  children?: React.ReactNode
}

const Panel = React.forwardRef<HTMLDivElement, PanelProps>(
  (
    {
      className,
      accordion = true,
      collapsible = false,
      panels,
      defaultValue = 0,
      value,
      onValueChange,
      children,
      ...props
    },
    ref
  ) => {
    // 计算默认值
    const getDefaultValue = () => {
      if (accordion) {
        // 手风琴模式：单个值
        if (typeof defaultValue === "number") {
          return `panel-${defaultValue}`
        }
        return `panel-0`
      } else {
        // 多开模式：数组
        if (Array.isArray(defaultValue)) {
          return defaultValue.map((i) => `panel-${i}`)
        }
        return [`panel-0`]
      }
    }

    // 渲染配置模式的面板
    const renderConfigPanels = () => {
      if (!panels || panels.length === 0) {
        return null
      }

      const childrenArray = React.Children.toArray(children)

      return panels.map((panel, index) => {
        const panelValue = `panel-${index}`
        return (
          <AccordionItem key={panelValue} value={panelValue}>
            <AccordionTrigger>{panel.title || `面板 ${index + 1}`}</AccordionTrigger>
            <AccordionContent
              forceMount={panel.forceRender}
            >
              {childrenArray[index] || (
                <div className="flex items-center justify-center h-full text-slate-400">
                  <p>面板内容区域 {index + 1}</p>
                </div>
              )}
            </AccordionContent>
          </AccordionItem>
        )
      })
    }

    // 渲染 children 模式的面板
    const renderChildrenPanels = () => {
      return children
    }

    return (
      <div
        ref={ref}
        className={cn("panel-container", className)}
        {...props}
      >
        <Accordion
          type={accordion ? "single" : "multiple"}
          {...(collapsible && { collapsible: true })}
          defaultValue={getDefaultValue()}
          value={value}
          onValueChange={onValueChange}
          className="w-full"
        >
          {panels && panels.length > 0 ? renderConfigPanels() : renderChildrenPanels()}
        </Accordion>
      </div>
    )
  }
)

Panel.displayName = "Panel"

export { Panel }

import * as React from "react"
import { cn } from "@/lib/utils"
import {
  Popover as ShadcnPopover,
  PopoverTrigger,
  PopoverContent,
} from "@/components/ui/popover"
import { Button } from "@/registry/components/button/button"

export interface PopoverProps extends React.HTMLAttributes<HTMLDivElement> {
  /**
   * 按钮文字
   */
  buttonName?: string
  /**
   * 隐藏按钮
   */
  hiddenBtn?: boolean
  /**
   * 禁用状态
   */
  disable?: boolean
  /**
   * 触发方式
   */
  trigger?: 'hover' | 'click'
  /**
   * 位置
   */
  placement?: 'top' | 'bottom' | 'left' | 'right'
  /**
   * 宽度
   */
  width?: number | string
  /**
   * 高度
   */
  height?: number | string
  /**
   * 是否打开
   */
  open?: boolean
  /**
   * 打开状态变化回调
   */
  onOpenChange?: (open: boolean) => void
  /**
   * 子元素
   */
  children?: React.ReactNode
}

const Popover = React.forwardRef<HTMLDivElement, PopoverProps>(
  (
    {
      className,
      buttonName = '气泡卡片',
      hiddenBtn = false,
      disable = false,
      trigger = 'click',
      placement = 'top',
      width = 200,
      height = 200,
      open,
      onOpenChange,
      children,
      ...props
    },
    ref
  ) => {
    // 内部状态管理（当 open 未受控时使用）
    const [internalOpen, setInternalOpen] = React.useState(false)

    // 判断是否受控
    const isControlled = open !== undefined
    const isOpen = isControlled ? open : internalOpen

    // 处理打开/关闭
    const handleOpenChange = (newOpen: boolean) => {
      if (!isControlled) {
        setInternalOpen(newOpen)
      }
      onOpenChange?.(newOpen)
    }

    // 计算内容样式
    const contentStyle = React.useMemo(() => {
      const style: React.CSSProperties = {}
      if (typeof width === 'number') {
        style.width = `${width}px`
      } else if (typeof width === 'string') {
        style.width = width
      }

      if (typeof height === 'number') {
        style.height = `${height}px`
      } else if (typeof height === 'string') {
        style.height = height
      }

      return style
    }, [width, height])

    // 渲染触发按钮
    const renderTrigger = () => {
      if (hiddenBtn) {
        return <div style={{ width: '100%', height: '100%' }} />
      }

      // hover 模式：使用 PopoverTrigger + 自定义鼠标事件处理
      if (trigger === 'hover') {
        return (
          <PopoverTrigger asChild>
            <div
              onMouseEnter={() => handleOpenChange(true)}
              onMouseLeave={() => handleOpenChange(false)}
              style={{ width: '100%', height: '100%' }}
            >
              <Button
                variant="outline"
                disabled={disable}
                style={{ width: '100%', height: '100%' }}
                onPointerDown={(e) => e.preventDefault()}
              >
                {buttonName}
              </Button>
            </div>
          </PopoverTrigger>
        )
      }

      // click 模式：使用 PopoverTrigger
      return (
        <PopoverTrigger asChild>
          <Button
            variant="outline"
            disabled={disable}
            style={{ width: '100%', height: '100%' }}
          >
            {buttonName}
          </Button>
        </PopoverTrigger>
      )
    }

    return (
      <div
        ref={ref}
        className={cn("popover-container", className)}
        style={{ height: '100%' }}
        {...props}
      >
        <ShadcnPopover
          open={isOpen}
          onOpenChange={handleOpenChange}
        >
          {renderTrigger()}

          <PopoverContent
            align={placement === 'left' || placement === 'right' ? 'center' : undefined}
            side={
              placement === 'top' ? 'top' :
              placement === 'bottom' ? 'bottom' :
              placement === 'left' ? 'left' :
              placement === 'right' ? 'right' : undefined
            }
            style={contentStyle}
            onOpenAutoFocus={(e: React.SyntheticEvent) => {
              // hover 模式下不自动聚焦
              if (trigger === 'hover') {
                e.preventDefault()
              }
            }}
          >
            <div
              className="popover-content"
              style={{
                width: '100%',
                height: '100%',
                overflow: 'auto'
              }}
            >
              {children}
            </div>
          </PopoverContent>
        </ShadcnPopover>
      </div>
    )
  }
)

Popover.displayName = "Popover"

