'use client'

import { useMemo, useEffect, useState, useCallback, useRef, type ReactNode } from 'react'
import _ from 'lodash'
import { api } from '@airiot/client'
import { useDatasetSet } from '@airiot/client'
import { ContextProvider } from '@/registry/components/container-context-provider/context-provider'

/**
 * 接口数据源配置
 */
export interface InterfaceDataConfig {
  op?: { key?: string }
  params?: { value?: Record<string, any> }
  predata?: boolean
  interval?: number
  submit?: string
}

export interface InterfaceDataSourceProps {
  id?: string
  op?: { key?: string }
  params?: { value?: Record<string, any> }
  predata?: boolean
  interval?: number
  submit?: string
  children?: ReactNode
}

// 默认配置
export const defaultInterfaceConfig: InterfaceDataConfig = {
  op: { key: 'device_max_values_Yglzib' },
  params: { value: {} },
  predata: false,
  interval: 0
}

/**
 * 过滤结果为图表格式
 */
const filterResult = (json: any): { dimensions: string[]; source: any[][] } => {
  let _json = json
  let dimensions: string[] = []
  let source: any[][] = []

  if (_.isPlainObject(_json)) {
    _json = [_json]
  } else if (!_.isArray(_json)) {
    _json = [{ result: _json }]
  }

  // 提取所有维度
  _json.forEach((item: any) => {
    const keys = _.keys(item)
    dimensions = _.union(dimensions, keys)
  })

  // 构建数据源
  _json.forEach((item: any) => {
    const values: any[] = []
    dimensions.forEach(key => {
      values.push(_.isArray(item[key]) ? JSON.stringify(item[key]) : item[key])
    })
    source.push(values)
  })

  return { dimensions, source }
}

/**
 * 接口数据源 Hook
 */
function useInterfaceData(config: InterfaceDataConfig) {
  const {
    op = { key: 'device_max_values_Yglzib' },
    params = { value: {} },
    predata = false,
    interval = 0,
    submit = '',
  } = config

  const [dataset, setDataset] = useState<any>(null)
  const [loading, setLoading] = useState(false)
  const [requestId, setRequestId] = useState<string | null>(null)

  const queryCallback = useRef<(() => void) | null>(null)
  const submitRef = useRef<string>('')

  // 过滤和转换数据
  const filterData = useCallback((data: any): any => {
    try {
      let result = data

      // 预处理数据
      if (predata) {
        result = filterResult(data)
      }

      return result
    } catch (error) {
      console.error('数据过滤失败:', error)
      return data
    }
  }, [predata])

  // 获取数据
  const fetchData = useCallback(async () => {
    const url = op?.key ? `ds/p/${op.key}` : null

    if (!url) {
      console.warn('接口key为空，无法获取数据')
      return
    }

    setLoading(true)

    try {
      const { json } = await api({ name: url }).fetch('', {
        method: 'POST',
        body: JSON.stringify(params?.value || {})
      })

      const filteredData = filterData(json)
      setDataset(filteredData)
      setRequestId(`${Date.now()}-${Math.random().toString(36).substring(2, 11)}`)
    } catch (error) {
      console.error('获取接口数据失败:', error)
      setDataset(null)
      setRequestId(`${Date.now()}-${Math.random().toString(36).substring(2, 11)}`)
    } finally {
      setLoading(false)
    }
  }, [op?.key, params, filterData])

  // 保存到 ref
  queryCallback.current = fetchData

  // submit 变化时手动触发
  useEffect(() => {
    if (submit && submit !== submitRef.current) {
      submitRef.current = submit
      queryCallback.current?.()
    }
  }, [submit])

  // 初始加载
  useEffect(() => {
    queryCallback.current?.()
  }, [])

  // 自动轮询
  useEffect(() => {
    if (!interval || interval <= 0) {
      return
    }

    const tick = () => {
      queryCallback.current?.()
    }

    const id = setInterval(tick, interval * 1000)
    return () => clearInterval(id)
  }, [interval])

  return {
    dataset,
    loading,
    fetchData,
    requestId
  }
}

export function InterfaceDataSource({
  id = 'interface-data-source',
  op = { key: 'device_max_values_Yglzib' },
  params = { value: {} },
  predata = false,
  interval = 0,
  submit,
  children
}: InterfaceDataSourceProps) {
  const datasetSet = useDatasetSet(id)

  // 使用接口数据
  const { dataset, loading, requestId } = useInterfaceData({
    op,
    params,
    predata,
    interval,
    submit
  })

  // 数据变化时：更新 atom
  useEffect(() => {
    datasetSet({ data: dataset, loading })
  }, [requestId, loading, datasetSet])

  // 准备 context 数据
  const contextData = useMemo(() => {
    return [{
      data: dataset,
      loading
    }]
  }, [requestId, loading])

  return (
    <ContextProvider data={contextData}>
      {children}
    </ContextProvider>
  )
}

'use client'

import { ReactNode, useEffect, useMemo, useState, useRef, useCallback } from 'react'
import _ from 'lodash'
import { api } from '@airiot/client'
import { useDatasetSet } from '@airiot/client'
import { ContextProvider } from '@/registry/components/container-context-provider/context-provider'
import { numberFormat, dateFormat } from '@/registry/lib/datasource-utils'

// ==================== Types ====================
const getQueryFilter = (filter: object) => filter
/**
 * 分组配置项
 */
export interface GroupItemConfig {
  field?: string
  dateOperator?: '天' | '周' | '月' | '年' | '一小时内的分钟数' | '一天内的小时数' | '一周内的天数' | '一月内的天数' | '一年内的天数' | '一年内的星期数' | '一年内的月数'
}

/**
 * 列配置项
 */
export interface ColumnItemConfig {
  name?: string
  field?: string
  accumulator?: '$count' | '$avg' | '$first' | '$last' | '$max' | '$min' | '$sum'
  expression?: any
}

/**
 * 排序配置项
 */
export interface SortItemConfig {
  value: string
  order?: 'ASC' | 'DESC'
}

/**
 * 字段格式化配置
 */
export interface FieldFormatConfig {
  field: string
  format: string
}

/**
 * 消息数据源配置
 */
export interface MessageDataConfig {
  initFilter?: Record<string, any>
  isGroup?: boolean
  group?: GroupItemConfig[]
  columns?: ColumnItemConfig[]
  fieldOrder?: SortItemConfig[]
  limit?: number
  interval?: number
  feildFormat?: FieldFormatConfig[]
  submit?: string
  requestId?: string
}

export interface MessageDataSourceProps {
  id?: string
  initFilter?: Record<string, any>
  isGroup?: boolean
  group?: Array<{
    field?: string
    dateOperator?: '天' | '周' | '月' | '年' | '一小时内的分钟数' | '一天内的小时数' | '一周内的天数' | '一月内的天数' | '一年内的天数' | '一年内的星期数' | '一年内的月数'
  }>
  columns?: Array<{
    name?: string
    field?: string
    accumulator?: '$count' | '$avg' | '$first' | '$last' | '$max' | '$min' | '$sum'
    expression?: any
  }>
  fieldOrder?: Array<{ value: string; order?: 'ASC' | 'DESC' }>
  limit?: number
  interval?: number
  feildFormat?: Array<{ field: string; format: string }>
  submit?: string
  children?: ReactNode
}

// 默认配置
export const defaultMessageConfig: MessageDataConfig = {
  initFilter: {},
  isGroup: false,
  group: [],
  columns: [],
  fieldOrder: [],
  limit: 3,
  interval: 0,
  feildFormat: []
}

// 消息字段列表
const messageList = [
  { label: '消息类型', value: 'messageType', type: 'string' },
  { label: '创建时间', value: 'createTime', type: 'time' },
  { label: '操作', value: 'optType', type: 'string' }
]

// ==================== Utility Functions ====================

/**
 * 生成日期操作
 */
const makeDateOperation = ({ dateOperator, field }: GroupItemConfig): any => {
  const fieldId = _.isObject(field) ? (field as any).id : field
  if (!fieldId) return null

  const $field = '$' + fieldId

  switch (dateOperator) {
    case '天':
      return { $dateToString: { format: '%Y-%m-%d', date: $field } }
    case '周':
      return { $dateToString: { format: '%Y-%V', date: $field } }
    case '月':
      return { $dateToString: { format: '%Y-%m', date: $field } }
    case '年':
      return { $year: $field }
    case '一小时内的分钟数':
      return { $minute: $field }
    case '一天内的小时数':
      return { $hour: $field }
    case '一周内的天数':
      return { $dayOfWeek: $field }
    case '一月内的天数':
      return { $dayOfMonth: $field }
    case '一年内的天数':
      return { $dayOfYear: $field }
    case '一年内的星期数':
      return { $week: $field }
    case '一年内的月数':
      return { $month: $field }
    default:
      return $field
  }
}

/**
 * 构建查询对象
 */
const makeQuery = (
  group: GroupItemConfig[] = [],
  columns: ColumnItemConfig[] = []
): { groupBy: Record<string, any>; groupFields: Record<string, any> } => {
  const groupBy: Record<string, any> = {}
  const groupFields: Record<string, any> = {}

  // 构建分组
  group.forEach(g => {
    if (!g.field) return

    const name = messageList?.find(m => m.value === g.field)?.label || g.field

    if (g.dateOperator) {
      groupBy[name] = makeDateOperation(g)
    } else {
      groupBy[name] = `$${g.field}`
    }
  })

  // 构建聚合字段
  columns.forEach(column => {
    const name = column.name || '个数'

    if (column.accumulator === '$count') {
      groupFields[name] = { $sum: 1 }
    }
  })

  return { groupBy, groupFields }
}

/**
 * 格式化字段
 */
const formatField = (
  field: string,
  value: any,
  feildFormat?: FieldFormatConfig[]
): any => {
  if (!feildFormat) return value

  const format = feildFormat.find(f => f.field === field)
  if (!format) return value

  const { field: fieldName, format: fieldFormat } = format

  if (fieldName === 'createTime' && fieldFormat) {
    return dateFormat(fieldFormat, value)
  } else {
    return numberFormat(fieldFormat, value)
  }
}

/**
 * 过滤和格式化数据
 */
const filterData = (
  data: any[],
  feildFormat?: FieldFormatConfig[]
): any[] => {
  return data.map(item => {
    const transformedData: Record<string, any> = {}

    Object.entries(item).forEach(([key, value]) => {
      transformedData[key] = formatField(key, value, feildFormat)
    })

    return transformedData
  })
}

// ==================== Main Hook ====================

/**
 * 消息数据源 Hook
 */
function useMessageData(config: MessageDataConfig) {
  const {
    initFilter = {},
    isGroup = false,
    group = [],
    columns = [],
    fieldOrder = [],
    limit = 1000,
    interval = 0,
    feildFormat = [],
    submit = '',
  } = config

  const [dataset, setDataset] = useState<any[]>([])
  const [loading, setLoading] = useState(false)
  const [requestId, setRequestId] = useState<string | null>(null)

  const queryCallback = useRef<(() => void) | null>(null)

  /**
   * 查询数据
   */
  const fetchData = useCallback(async () => {
    try {
      setLoading(true)

      const filter = getQueryFilter(initFilter)

      let query: any = {
        project: {
          isDelete: 1,
          data: 1,
          messageType: 1,
          optType: 1,
          record: 1,
          createTime: 1
        },
        filter,
        sorts: fieldOrder?.map(order => ({ [order.value]: order.order === 'ASC' ? 1 : -1 }))
      }

      // 分组查询
      if (isGroup && group && group.length > 0) {
        const { groupBy, groupFields } = makeQuery(group, columns)
        query.groupBy = groupBy
        query.groupFields = groupFields
      }

      // 设置分页
      query.limit = limit || 1000

      // 执行查询
      const queryString = encodeURIComponent(JSON.stringify(query))
      const { json } = await api({ name: 'core/message' }).fetch(`?query=${queryString}`)

      // 格式化数据
      const data = filterData(json || [], feildFormat)
      setDataset(data)
      setRequestId(`${Date.now()}-${Math.random().toString(36).substring(2, 9)}`)
    } catch (error) {
      console.error('查询消息数据失败:', error)
      setDataset([])
      setRequestId(`${Date.now()}-${Math.random().toString(36).substring(2, 9)}`)
    } finally {
      setLoading(false)
    }
  }, [initFilter, isGroup, group, columns, fieldOrder, limit, feildFormat])

  // 保存到 ref
  queryCallback.current = fetchData

  // requestId 或关键参数变化时触发查询
  useEffect(() => {
    fetchData()
  }, [JSON.stringify({ initFilter, fieldOrder, feildFormat, submit })])

  // 自动轮询
  useEffect(() => {
    if (!interval || interval <= 0) {
      return
    }

    const tick = () => {
      queryCallback.current?.()
    }

    const id = setInterval(tick, interval * 1000)
    return () => clearInterval(id)
  }, [interval])

  return {
    dataset,
    loading,
    requestId
  }
}

/**
 * 消息数据源组件 - 纯容器，不包含任何布局和样式
 * 内部集成 ContextProvider，子组件通过 useContextProvider 获取数据
 * 优化：只在查询参数变化时更新数据，避免大数据集的不必要比较
 */
export function MessageDataSource({
  id = 'message-data-source',
  initFilter = {},
  isGroup = false,
  group = [],
  columns = [],
  fieldOrder = [],
  limit = 3,
  interval = 0,
  feildFormat = [],
  submit,
  children
}: MessageDataSourceProps) {
  // 使用消息数据
  const { dataset, loading, requestId } = useMessageData({
    initFilter,
    isGroup,
    group,
    columns,
    fieldOrder,
    limit,
    interval,
    feildFormat,
    submit
  })

  const setDataset = useDatasetSet(id)

  useEffect(() => {
    setDataset({ data: dataset, loading })
  }, [requestId, loading, setDataset])

  const contextData = useMemo(() => {
    return [{ data: dataset, loading }]
  }, [requestId, loading])

  return (
    <ContextProvider data={contextData}>
      {children}
    </ContextProvider>
  )
}

import _ from 'lodash'
import dayjs from 'dayjs'

/**
 * 生成时间查询条件
 * @param timeRange 时间范围配置
 * @returns 查询条件数组或 null
 */
export const timeQuery = (timeRange: any) => {
  const { type, count, unit, fromNow, time, range, historyTime } = timeRange
  const start = historyTime ? dayjs(historyTime) : dayjs()
  const end = historyTime ? dayjs(historyTime) : dayjs()

  if (type == 'forward' && count && unit) {
    if (!fromNow) {
      return [
        `time >= '${start.startOf(unit).subtract(count, unit).toISOString()}'`,
        `time < '${end.startOf(unit).toISOString()}'`
      ]
    } else {
      return [
        `time >= '${start.subtract(count, unit).toISOString()}'`,
        `time < '${end.toISOString()}'`
      ]
    }
  }

  if (type == 'backward' && count && unit) {
    if (!fromNow) {
      return [
        `time < '${start.endOf(unit).add(count, unit).toISOString()}'`,
        `time > '${end.endOf(unit).toISOString()}'`
      ]
    } else {
      return [
        `time < '${start.add(count, unit).toISOString()}'`,
        `time > '${end.toISOString()}'`
      ]
    }
  }

  if (type == 'now' && unit) {
    return [`time > '${start.startOf(unit).toISOString()}'`, `time <= '${end.toISOString()}'`]
  }

  if (type == 'before' && time) {
    return [`time < '${dayjs(time).toISOString()}'`]
  }

  if (type == 'after' && time) {
    return [`time >= '${dayjs(time).toISOString()}'`]
  }

  if (type == 'between' && range && range.lte && range.gte) {
    return [
      `time >= '${dayjs(range.gte).toISOString()}'`,
      `time <= '${dayjs(range.lte).toISOString()}'`
    ]
  } else if (type === 'between' && range && range.financialMonth) {
    // 处理财务月时间范围
    const { financialMonth } = range
    const { date: financialDate, time: financialTime } = range.financialMonth || {}

    if (financialMonth && financialDate && financialTime) {
      // 解析财务月，格式如 "2025-02"
      const [year, month] = financialMonth.split('-').map(Number)

      // 计算财务月开始时间：当前月的指定日期和时间
      const startTime = dayjs()
        .year(year)
        .month(month - 1) // dayjs的月份从0开始
        .date(financialDate)
        .startOf('day')
        .add(dayjs.duration(financialTime))

      // 计算财务月结束时间：下个月的指定日期和时间减1秒
      const endTime = dayjs(startTime)
        .add(1, 'month')
        .subtract(1, 'second')

      return [
        `time >= '${startTime.toISOString()}'`,
        `time <= '${endTime.toISOString()}'`
      ]
    }
  }

  return null
}

/**
 * 数字格式化
 */
export const numberFormat = (format: string, value: any): any => {
  const num = Number(value)
  if (isNaN(num)) {
    return null
  }

  let result: any = num
  const regex = /^[0-9]$/

  if (format && !regex.test(format)) {
    // 预定义格式
    switch (format) {
      case 'percent':
        result = _.isNumber(result) ? (_.round(result * 100) + '%') : (result || 'n/a')
        break
      case 'percentPoint':
        result = _.isNumber(result) ? (_.round(result * 100, 2) + '%') : (result || 'n/a')
        break
      case 'thousandth':
        result = _.isNumber(result) ? _.round(result).toLocaleString() : (result || 'n/a')
        break
      case 'thousandthPoint':
        result = _.isNumber(result) ? _.round(result, 2).toLocaleString() : (result || 'n/a')
        break
      default:
        break
    }
  } else {
    // 保留 X 位小数
    result = result.toFixed(parseInt(format) || 0)
  }

  if (_.isNaN(result) || result === 'NaN') {
    result = null
  }

  return result
}

/**
 * 日期格式化
 */
export const dateFormat = (format: string, value: any): any => {
  if (!value) {
    return null
  }

  const t = dayjs(value)
  let time: any = t

  switch (format) {
    case '秒级时间戳':
      time = t.unix().toString()
      break
    case '毫秒级时间戳':
      time = t.valueOf().toString()
      break
    case '历史数据时间':
      time = t.toISOString()
      break
    default:
      time = t.format(format)
      break
  }

  if (time === 'Invalid Date') {
    time = null
  }

  return time
}

'use client'

import { useMemo, useEffect, useState, useCallback, type ReactNode } from 'react'
import _ from 'lodash'
import { api, useWS } from '@airiot/client'
import { useDatasetSet } from '@airiot/client'
import dayjs from 'dayjs'
import { toast } from '@/hooks/use-toast'
import { ContextProvider } from '@/registry/components/container-context-provider/context-provider'
import type {
  TagValue,
  TagConfig,
  TimeLineConfig,
  DataPoint,
  Dimension,
  QueryResult,
  WSMessageData,
  UseWSReturn
} from '@/registry/lib/datasource-types'

// ==================== Types ====================

/**
 * 实时数据配置
 */
export interface RealtimeDataConfig {
  tags?: TagConfig[]
  timeLine?: TimeLineConfig
  xFormat?: string
  submit?: string
}

export interface RealtimeDataSourceProps {
  id?: string
  tags?: TagConfig[]
  timeLine?: TimeLineConfig
  xFormat?: string
  interval?: number
  submit?: string
  children?: ReactNode
}

// 重新导出类型，方便外部使用
export type { TagValue, TagConfig, TimeLineConfig, DataPoint, Dimension, QueryResult, WSMessageData, UseWSReturn }

// 默认配置
export const defaultRealtimeConfig: RealtimeDataConfig = {
  tags: [{
    tableData: { id: '6912cc842e0f29806c78bce5', table: { id: 'A' } },
    tag: { id: 'a', name: '测试a' }
  }],
  timeLine: { count: 5, unit: 'm' },
  xFormat: 'YYYY-MM-DD HH:mm:ss',
  submit: ''
}

// ==================== Utility Functions ====================

/**
 * 数字保留指定小数位
 */
const toFixed = (value: number, precision: number = 2): number | null => {
  if (!_.isNumber(value)) {
    return value
  }
  return Math.round(value * Math.pow(10, precision)) / Math.pow(10, precision)
}

/**
 * 构建标签的唯一键
 */
const buildTagKey = (tagId: string | undefined, tableDataId: string | undefined): string => {
  if (!tagId || !tableDataId) return 'unknown'
  return `${tableDataId}-${tagId}`
}

/**
 * 获取历史数据
 */
const fetchHistoryData = async (where: string): Promise<Record<string, any[]>> => {
  try {
    const { json: { results } } = await api({ name: 'core/data' })
      .fetch('/query', {
        method: 'POST',
        body: where
      })

    if (!results || results.length === 0) {
      return {}
    }

    const data: Record<string, any[]> = {}

    results.forEach((item: any) => {
      if (item?.series) {
        const point = item.series[0]
        if (point?.values) {
          const tagId = point.columns?.[1]
          const tableDataId = point.values?.[0]?.[2]
          const key = buildTagKey(tagId, tableDataId)
          data[key] = point.values.slice().reverse().map((v: any) => [
            new Date(v[0]),
            v[1],
            v[2]
          ])
        }
      }
    })

    return data
  } catch (err: any) {
    const errorMessage = err.json?.data || err.message || err?.json?.detail || err?.detail || '获取历史数据失败'
    toast({
      variant: 'destructive',
      title: errorMessage
    })
    throw err
  }
}

/**
 * 按 tags 顺序排序数据集
 */
const sortByTags = (
  dataset: QueryResult[],
  tags: TagConfig[]
): QueryResult[] => {
  if (!Array.isArray(dataset) || dataset.length === 0) {
    return []
  }

  if (!Array.isArray(tags) || tags.length === 0) {
    return dataset.slice()
  }

  const tagOrderMap = new Map<string, number>()

  tags.forEach((tag, index) => {
    if (!tag) return

    const tableData = tag.tableData
    const tagValue = tag.tag

    if (!tableData?.id || !tagValue?.id) {
      return
    }

    const key = buildTagKey(tagValue.id, tableData.id)
    tagOrderMap.set(key, index)
  })

  return dataset.slice().sort((a, b) => {
    const aOrder = a.key !== undefined ? tagOrderMap.get(a.key) ?? Infinity : Infinity
    const bOrder = b.key !== undefined ? tagOrderMap.get(b.key) ?? Infinity : Infinity
    return aOrder - bOrder
  })
}

/**
 * 格式化时间
 */
const formatTime = (time: Date | string, xFormat?: string): Date | string => {
  return xFormat ? dayjs(time).format(xFormat) : new Date(time)
}

/**
 * 查找标签名称
 */
const findTagName = (tags: TagConfig[], key: string): string => {
  const tag = tags.find(t => {
    const tagId = t.tag?.id || t.id
    const tableDataId = t.tableData?.id
    const tagKey = buildTagKey(tagId, tableDataId)
    return tagKey === key
  })

  if (!tag) return ''

  // 返回标题或组合名称
  return tag.title ||
    tag.name ||
    `${tag.tableData?.name || ''}-${tag.tag?.name || ''}`
}

/**
 * 获取标签项
 */
const getTagItem = (tags: TagConfig[], key: string): TagConfig | undefined => {
  return tags.find(d => {
    const tagId = d.tag?.id || d.id
    const tableDataId = d.tableData?.id
    const tagKey = buildTagKey(tagId, tableDataId)
    return tagKey === key
  })
}

// ==================== Main Hook ====================

/**
 * 实时数据 Hook
 */
function useRealtimeData(config: RealtimeDataConfig) {
  const {
    tags = [],
    timeLine = { count: 1, unit: 'h' },
    xFormat,
    submit,
  } = config

  const [dataset, setDataset] = useState<QueryResult[]>([])
  const [loading, setLoading] = useState(false)
  const [requestId, setRequestId] = useState<string | null>(null)

  // 使用 WebSocket（在顶层调用 hook）
  const { subscribe, onData } = useWS()

  /**
   * 处理标签数据
   * 只支持标准格式：tableData 和 tag
   */
  const processTags = useCallback((inputTags: TagConfig[]) => {
    return (inputTags || [])
      .filter(t => t?.tag?.id && t?.tableData?.id) as TagConfig[]
  }, [])

  const subTags = useMemo(() => processTags(tags), [tags, processTags])

  /**
   * 获取历史数据
   */
  const fetchHistory = useCallback(async () => {
    if (subTags.length === 0) {
      setDataset([])
      return
    }

    const isLastPoint = !(timeLine?.count)
    const timeWhere = isLastPoint
      ? []
      : [`time >= now() - ${timeLine.count || 1}${timeLine.unit || 'h'}`]

    const where = subTags
      .map(s => {
        // 获取标签ID
        const tagId = s?.tag?.id || s?.id

        // 获取表ID
        const tableId = s?.table?.id || s?.tableData?.table?.id

        // 获取表数据ID
        const tableDataId = s?.tableData?.id

        if (!tableId || !tableDataId || !tagId) {
          return null
        }

        return {
          fields: [isLastPoint ? `LAST("${tagId}") AS "${tagId}"` : `"${tagId}"`, 'id'],
          order: 'time desc',
          id: tableDataId,
          tableId: tableId,
          where: timeWhere
        }
      })
      .filter(Boolean)

    if (where.length === 0) {
      setDataset([])
      return
    }

    try {
      setLoading(true)

      const data = await fetchHistoryData(JSON.stringify(where))

      // 确保所有标签都有数据
      where.forEach(item => {
        if (!item || !item.fields || !item.fields[0]) return
        const key = buildTagKey(item.id, item.fields[0].split('"')[1])
        if (!data[key]) {
          data[key] = []
        }
      })

      let result: QueryResult[]

      if (isLastPoint) {
        // 获取最新数据点
        const dimensions: Dimension[] = [
          { name: 'time', title: '时间', type: xFormat ? 'ordinal' : 'time' },
          { name: 'value', title: '数据值', type: 'number' },
          { name: 'name', title: '名称', type: 'ordinal' },
          { name: 'key', title: '标识', type: 'ordinal' }
        ]

        const source = Object.keys(data).map(key => {
          const item = getTagItem(subTags, key)
          const name = findTagName(subTags, key)
          const tag = item?.tag
          const itemKey = buildTagKey(
            tag?.id || item?.tableData?.id,
            tag?.id || item?.id
          )
          const value = data[key].length > 0
            ? toFixed(data[key][0][1], !_.isNil(item?.fixed) ? item?.fixed : 3)
            : null
          const time = data?.[key]?.[0]?.[0] || null

          return [
            formatTime(time, xFormat),
            value,
            name,
            itemKey
          ]
        })

        result = [{ dimensions, source }]
      } else {
        // 获取历史数据序列
        result = Object.keys(data).map(key => {
          const item = getTagItem(subTags, key)
          const tag = item?.tag
          const node = item?.tableData
          const name = item?.title ||
            `${node?.name || node?.title || node?.id || ''}-${tag?.name || item?.name || key}`

          return {
            key,
            title: name,
            dimensions: [
              { name: 'time', title: '时间', type: xFormat ? 'ordinal' : 'time' },
              { name: name || key, type: 'number', tag: key }
            ],
            source: data[key].map(d => [
              formatTime(d[0], xFormat),
              toFixed(d[1], !_.isNil(item?.fixed) ? item?.fixed : 3),
              d[2]
            ])
          }
        })
      }

      setDataset(sortByTags(result, subTags))
      setRequestId(`${Date.now()}-${Math.random().toString(36).substring(2, 11)}`)
    } catch (err) {
      console.error('获取历史数据失败:', err)
      setDataset([])
      setRequestId(`${Date.now()}-${Math.random().toString(36).substring(2, 11)}`)
    } finally {
      setLoading(false)
    }
  }, [subTags, timeLine, xFormat])

  /**
   * 处理 WebSocket 数据更新
   */
  const handleWsData = useCallback((data: any) => {
    if (subTags.length === 0) return

    const payload: Array<{ key: string; value: number; time: Date | string }> = []

    if (data && _.isPlainObject(data)) {
      const tableDataId = data.tableDataId || data.id
      const fields = data.fields
      const time = new Date(data?.time || Date.now())

      Object.keys(fields).forEach(tagId => {
        const key = buildTagKey(tagId, tableDataId)
        const value = fields[tagId]
        payload.push({
          key,
          value,
          time: formatTime(time, xFormat)
        })
      })
    }

    setDataset(prevDataset => {
      if (!prevDataset || prevDataset.length === 0) {
        return prevDataset
      }

      // 只处理数组格式（实时数据总是返回数组）
      const newDataset = prevDataset.map(d => {
        let newD = { ...d }
        payload.forEach(p => {
          if (p.key === d.key || !d.key) {
            const source = _.cloneDeep(d.source || []) as any[][]
            if (source.length > 0) {
              source.shift()
              source.push([p.time, p.value, findTagName(subTags, p.key), p.key])
            }
            newD = { ...newD, source }
          }
        })
        return newD
      })

      return sortByTags(newDataset, subTags)
    })
  }, [subTags, xFormat])

  // 初始加载
  useEffect(() => {
    fetchHistory()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  // 提交时重新获取历史数据
  useEffect(() => {
    if (submit) {
      fetchHistory()
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [submit])

  /**
   * 订阅实时数据更新
   */
  useEffect(() => {
    if (subTags.length === 0) return

    // 构建订阅标签
    const subTagList = subTags.map(t => {
      return {
        tagId: t.tag?.id || t.id,
        tableId: t.table?.id || t.tableData?.table?.id,
        dataId: t.tableData?.id
      }
    }).filter(item => item?.tagId && item?.tableId && item?.dataId)

    if (subTagList.length === 0) return

    // 注册数据回调
    onData(handleWsData)

    // 订阅实时数据
    const unsubscribe = subscribe('data', subTagList)

    // 返回清理函数
    return () => {
      unsubscribe?.()
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [subTags])

  return {
    dataset,
    loading,
    fetchData: fetchHistory,
    requestId
  }
}

export function RealtimeDataSource({
  id = 'realtime-data-source',
  tags = [],
  timeLine = { count: 5, unit: 'm' },
  xFormat = 'YYYY-MM-DD HH:mm:ss',
  submit,
  children
}: RealtimeDataSourceProps) {
  const datasetSet = useDatasetSet(id)

  // 使用实时数据
  const { dataset, loading, requestId } = useRealtimeData({
    tags,
    timeLine,
    xFormat,
    submit
  })

  // 数据变化时：更新 atom
  useEffect(() => {
    datasetSet({ data: dataset, loading })
  }, [requestId, loading, datasetSet])

  // 准备 context 数据
  const contextData = useMemo(() => {
    return [{
      data: dataset,
      loading
    }]
  }, [requestId, loading])

  return (
    <ContextProvider data={contextData}>
      {children}
    </ContextProvider>
  )
}

/**
 * 数据源类型定义
 * 统一历史数据和实时数据的数据点结构
 *
 * 数据层级关系：
 * Table (表) -> TableData (表数据/设备) -> Tag (标签/数据点)
 */

// ==================== 基础数据类型 ====================

/**
 * 表信息（Table）
 * 定义一个表的基本信息
 * @example
 * { id: 'A', name: '设备表' }
 */
export interface TableInfo {
  id: string
  name?: string
  title?: string
  tableMajorType?: string  // 表类型，如 'device'
  [key: string]: any
}

/**
 * 表数据信息（TableData）
 * 表中的某条记录，如某个设备
 * @example
 * {
 *   id: 'A001',
 *   name: '1号设备',
 *   table: { id: 'A', name: '设备表' }
 * }
 */
export interface TableDataInfo {
  id: string
  name?: string
  title?: string
  table: TableInfo
  tabledata?: string  // 表数据ID（向后兼容）
  [key: string]: any
}

/**
 * 标签信息（Tag）
 * 表数据上的某个数据点/字段
 * @example
 * { id: 'temperature', name: '温度' }
 * @example with tableData
 * { id: 'temperature', name: '温度', tableData: { id: 'A001', table: { id: 'A' } } }
 */
export interface TagInfo {
  id: string
  name?: string
  tableData?: TableDataInfo
}

// ==================== 标签配置类型 ====================

/**
 * 标签值（TagValue）
 * 标签的唯一标识符，用于快速定位
 * @example
 * {
 *   tableId: 'A',
 *   tableDataId: 'A001',
 *   tagId: 'temperature'
 * }
 */
export interface TagValue {
  tableId: string
  tableDataId: string
  tagId: string
}

/**
 * 标签配置（TagConfig）
 * 完整的数据点配置，包含表、表数据、标签的完整信息
 *
 * 支持两种输入格式：
 * 1. 直接格式（推荐）：直接提供 table、tableData、tag 对象
 * 2. 简写格式：使用 tableDataTag.value 提供标签值
 *
 * @example 直接格式
 * {
 *   table: { id: 'A', name: '设备表' },
 *   tableData: { id: 'A001', name: '1号设备', table: { id: 'A' } },
 *   tag: { id: 'temperature', name: '温度' },
 *   title: '1号设备温度',
 *   fixed: 2
 * }
 *
 * @example 简写格式
 * {
 *   tableDataTag: {
 *     value: { tableId: 'A', tableDataId: 'A001', tagId: 'temperature' },
 *     name: '1号设备温度'
 *   }
 * }
 */
export interface TagConfig {
  // ==================== 方式1：直接格式（推荐） ====================

  /**
   * 表信息
   */
  table?: TableInfo

  /**
   * 表数据信息（设备等）
   */
  tableData?: TableDataInfo

  /**
   * 标签信息（数据点）
   */
  tag?: TagInfo

  // ==================== 方式2：tableDataTag 简写格式（向后兼容） ====================

  /**
   * tableDataTag 配置格式
   * value: 标签的唯一标识符
   * name: 显示名称
   */
  tableDataTag?: {
    value?: TagValue
    name?: string
  }

  // ==================== 通用配置属性 ====================

  /**
   * 数据点标题/显示名称
   * 优先级最高，用于图表显示
   */
  title?: string

  /**
   * 数据点名称
   */
  name?: string

  /**
   * 唯一键，用于数据标识
   */
  key?: string

  /**
   * 唯一标识符（向后兼容）
   */
  uid?: string
  id?: string

  /**
   * 表ID字符串（简写，向后兼容）
   */
  tableId?: string

  /**
   * 分组相关
   */
  group?: string
  groupType?: 'id' | 'department' | 'other'

  /**
   * 数据格式化
   */
  fixed?: number  // 保留小数位数
  func?: string   // 聚合函数

  /**
   * 查询相关
   */
  fields?: string[]
  query?: Array<Array<{ field?: string; method?: string }>>

  /**
   * 其他扩展属性
   */
  [key: string]: any
}

/**
 * 数据点配置（TagConfig 的别名）
 */
export type DataPointConfig = TagConfig
export type DataItemConfig = TagConfig

/**
 * 列配置
 */
export interface ColumnConfig {
  field?: string
  tableData?: TableDataInfo
  table?: TableInfo
  groupType?: 'id' | 'department' | 'other'
  group?: string
}

// ==================== 查询结果类型 ====================

/**
 * 数据维度
 */
export interface Dimension {
  name: string
  title?: string
  type: string
  tag?: string
}

/**
 * 数据点
 */
export interface DataPoint {
  time: Date | string
  value: number | null
  name?: string
