// ==================== 时间配置类型 ====================

/**
 * 时间范围配置
 */
export interface TimeRangeConfig {
  type?: 'forward' | 'backward' | 'custom'
  range?: {
    radioType?: number
    gte?: string
    lte?: string
    date?: string
    financialMonth?: {
      date?: number
      time?: string
    }
