// ==================== Table Data 类型 ====================

/**
 * 字段配置
 */
export interface FieldConfig {
  id?: string
  key?: string
  type?: string
  title?: string
  name?: string
  propertyType?: string
  tableName?: string
  transform?: (value: any) => any
  config?: string
  enum1?: any[]
  enum_title1?: any[]
  [key: string]: any
}

/**
 * Schema 结构
 */
export interface Schema {
